// Auto-generated: quiz content for Cours23 — translations can be added per-locale.
// Structural data arrays (DEGREES, MODES, etc.) remain in the component for now.

export interface Question { q: string; opts: string[]; a: number; fb: string; }
export interface Cours23Locale { questions: Question[]; }

const questionsFr: Question[] = [
  // Identifier le style
  { q: "Quelle progression est caractéristique du style Bach ?", opts: ["CMaj7–B♭Maj7–A♭Maj7 (parallélisme)","CMaj–Am–Dm7–G7 (cycle des quintes)","GMaj–FMaj–CMaj (mixolydien)","Dm9–G13–CMaj9 (jazz extensions)"], a: 1, fb: "I–VIm–IIm–V7 est le cycle des quintes descendant de Bach. Chaque accord est à distance de quinte du suivant. La résolution G7→C résout le triton B–F. C'est le mouvement harmonique fondamental du contrepoint baroque." },
  { q: "La basse d'Alberti (gauche : bas–milieu–haut–milieu) est caractéristique de :", opts: ["Bach","Mozart","Chopin","Debussy"], a: 1, fb: "La basse d'Alberti est une figure d'accompagnement caractéristique du style classique (Mozart, Haydn). La main gauche alterne basse–accord–milieu–accord, créant un accompagnement fluide et symétrique sous la mélodie de la main droite." },
  { q: "L'emprunt IVm (ex. Fm7 en C) dans les nocturnes est caractéristique de :", opts: ["Bach","Mozart","Chopin","Debussy"], a: 2, fb: "Fm7 (IVm) en C majeur est l'emprunt romantique par excellence de Chopin. Il emprunte le IVm au mode mineur parallèle (C mineur), créant une couleur sombre inattendue. Cette technique est rarement utilisée par Bach ou Mozart." },
  { q: "Les accords Maj7 parallèles sans résolution de dominante sont caractéristiques de :", opts: ["Bach","Mozart","Chopin","Debussy"], a: 3, fb: "Debussy (impressionnisme) fait glisser des blocs d'accords parallèles — Maj7, 9e, accords de quintes — sans jamais résoudre vers une dominante. La couleur prime sur la fonction harmonique." },
  { q: "II–V–I avec extensions (9e, 13e) et voicings sans quinte caractérisent :", opts: ["Rock modal","Jazz post-bop (Evans)","Romantique","Baroque (Bach)"], a: 1, fb: "Le jazz post-bop (Bill Evans, Brad Mehldau) utilise II–V–I enrichi d'extensions — 9e sur II, 13e sur V, 9te sur I. Les voicings omettent la quinte (neutre) pour garder 3ce, 7te et extensions colorantes." },
  { q: "I–♭VII–IV–I sans dominante fonctionnelle est la progression du :", opts: ["Style Chopin","Style baroque","Rock modal (mixolydien)","Jazz bebop"], a: 2, fb: "I–♭VII–IV–I est la progression rock modal par excellence. Le ♭VII vient du mode mixolydien (7te mineure). Cette progression peut se répéter indéfiniment sans résolution V→I — Norwegian Wood, Creep, Hey You." },
  { q: "Relations de tierces descendantes et emprunts dramatiques au mineur caractérisent :", opts: ["Style Mozart","Style Debussy","Style Bach","Romantisme tardif (Rachmaninov)"], a: 3, fb: "Le romantisme tardif (Rachmaninov, Tchaïkovski) exploite les relations de tierces (I→♭VI→IV) et les emprunts dramatiques au mineur. La densité harmonique est maximale, les pédales de dominante longues." },
  { q: "Quel style utilise le contrepoint le plus rigoureux ?", opts: ["Jazz","Romantique","Bach (baroque)","Rock modal"], a: 2, fb: "Bach est le maître du contrepoint strict. Ses règles : pas de quintes parallèles, pas d'octaves parallèles, résolution obligatoire du triton, voix intérieures avec mouvement mélodique indépendant. Ces règles définissent le contrepoint à 4 voix (SATB)." },
  { q: "Quel style évite le plus les dominantes fonctionnelles V7→I ?", opts: ["Debussy (impressionnisme)","Bach","Mozart","Jazz bebop"], a: 0, fb: "Debussy évite systématiquement la résolution V7→I qu'il trouve trop prévisible. À la place, il fait glisser des accords parallèles ou utilise des gammes par tons. Cette liberté par rapport à la tonalité fonctionnelle est la signature de l'impressionnisme." },
  { q: "La symétrie 4+4 mesures (antécédent + conséquent) est caractéristique de :", opts: ["Romantique","Jazz modal","Mozart (classique)","Debussy"], a: 2, fb: "La forme période (4+4 mesures) est la cellule de base du style classique viennois — Mozart, Haydn, Beethoven jeune. L'antécédent (4 mesures finissant sur V) est répondu par le conséquent (4 mesures finissant sur I). Symétrie et clarté absolues." },
  { q: "La gamme par tons (6 notes équidistantes, aucun demi-ton) est associée à :", opts: ["Bach","Jazz bebop","Debussy","Rock modal"], a: 2, fb: "Debussy utilise la gamme par tons (C D E F# G# Bb) comme couleur harmonique. Sans demi-ton, elle crée une flottaison ambiguë — pas de sens tonal établi, pas de sensible. C'est l'une des signatures de l'impressionnisme." },
  { q: "La substitution tritonique (G7 → D♭7) est surtout utilisée dans :", opts: ["Style Bach","Style Mozart","Style Debussy","Jazz (bebop/post-bop)"], a: 3, fb: "La substitution tritonique est une technique jazz développée dans le bebop (années 1940). Elle remplace V7 par l'accord de dominante situé un triton plus bas, créant une basse chromatique descendante (♭II→I)." },
  { q: "Les progressions cycliques sans résolution finale sont typiques de :", opts: ["Bach","Mozart","Rock modal","Chopin"], a: 2, fb: "Le rock modal utilise des progressions cycliques (I–♭VII–IV–I) qui peuvent se répéter indéfiniment. Il n'y a pas de besoin de résolution finale V→I. C'est la grande différence avec le style tonal classique." },
  { q: "La densité harmonique maximale avec voix nombreuses est caractéristique de :", opts: ["Debussy","Mozart","Romantisme tardif","Jazz modal"], a: 2, fb: "Rachmaninov et Tchaïkovski écrivent des textures orchestralement denses, avec de nombreuses voix doublées, des accords riches et un chromatisme généralisé. C'est l'apogée du romantisme — tout le contraire de l'économie de Mozart." },
  { q: "Quelle progression identifie le plus clairement un style impressionniste de Debussy ?", opts: ["I–IV–V7–I","I–♭VI–IV–V","CMaj7–B♭Maj7–A♭Maj7–G♭Maj7","Dm9–G13–CMaj9"], a: 2, fb: "Quatre Maj7 descendant par tons entiers sans résolution — c'est le parallélisme impressionniste de Debussy. Pas de V7→I, pas de tension-résolution. Chaque accord est une couleur autonome qui 'glisse' vers la suivante." },
  // Techniques spécifiques
  { q: "Pourquoi Bach évite-t-il les quintes parallèles ?", opts: ["Elles sont trop difficiles à jouer","Elles créent une dissonance de 'quinte cachée' interdite en contrepoint strict","Elles ne sonnent pas bien sur le clavecin","Elles étaient interdites par l'Église"], a: 1, fb: "Les quintes parallèles ('fifths parallèles') créent une 'quinte cachée' (hidden 5th) dans le contrepoint strict — deux voix se déplacent dans le même sens et tombent sur une quinte. Ce mouvement réduit l'indépendance des voix, règle fondamentale du contrepoint à 4 voix." },
  { q: "Le 'cycle des quintes descendant' en C majeur donne :", opts: ["C – G – D – A – E – B – F# – C","C – F – Bdim – Em – Am – Dm – G – C","C – Am – Em – G – Dm – F – C","C – Dm – Em – F – G – Am – Bdim – C"], a: 1, fb: "Le cycle des quintes descendant : C→F→B→E→A→D→G→C. En C majeur diatonique : CMaj – FMaj – Bdim – Em – Am – Dm – G7 – CMaj. Chaque accord descend d'une quinte (ou monte d'une quarte). C'est la progression harmonique fondamentale de la musique baroque." },
  { q: "La gamme par tons de Debussy contient combien de notes ?", opts: ["5 (pentatonique)","6 (hexatonique)","7 (diatonique)","8 (octatonique)"], a: 1, fb: "La gamme par tons est hexatonique — 6 notes équidistantes d'un ton entier : C D E F# G# Bb (puis retour à C). L'absence de demi-ton lui donne son ambiguïté tonale caractéristique. On l'appelle aussi 'gamme de Debussy'." },
  { q: "Un voicing jazz 'sans quinte' omit la 5te car :", opts: ["La quinte est difficile à jouer","La quinte (5te juste) est acoustiquement neutre et apporte peu de couleur","La quinte n'existe pas dans la gamme pentatonique","La quinte crée un parallélisme interdit"], a: 1, fb: "La quinte juste est acoustiquement la plus consonante après l'octave — elle ne colore pas l'accord. En jazz, on garde 3ce+7te (guide-tones) et on ajoute 9te, 11e (#4), 13te. La quinte est souvent omise pour garder les voicings serrés et expressifs." },
  { q: "La progression I–♭VII–IV–I est mixolydienne car :", opts: ["Elle contient 3 accords majeurs","Le ♭VII vient du mode mixolydien (7te mineure du ton)","Elle évite la tonique","Elle descend par quintes"], a: 1, fb: "En G mixolydien, la 7te est F naturel (pas F#). L'accord construit sur ce F naturel est FMaj (♭VIIMaj) — un accord majeur étranger à G majeur mais naturel en G mixolydien. C'est la note caractéristique qui distingue mixolydien de ionien." },
  { q: "Un emprunt 'à l'homonyme' signifie :", opts: ["Emprunter d'une tonalité voisine (quinte)","Emprunter au mode parallèle (même tonique, mode différent : C majeur ↔ C mineur)","Emprunter d'une gamme pentatonique","Emprunter d'un accord de dominante secondaire"], a: 1, fb: "L'emprunt à l'homonyme (ou mode parallèle) utilise des accords de la tonalité de même nom mais de mode différent. En C majeur, emprunter Fm7 (IVm de C mineur) est un emprunt à l'homonyme — même tonique C, mais couleur mineure." },
  { q: "Le rythme harmonique 'rapide' en jazz signifie :", opts: ["Tempo rapide","2 accords par mesure ou plus (vs 1 accord par 2-4 mesures)","Tous les accords sont des croches","Beaucoup de syncopes"], a: 1, fb: "Le rythme harmonique est la fréquence des changements d'accords. En jazz bebop/post-bop, il est souvent rapide : 2 accords par mesure (ou plus dans les Coltrane Changes). Mozart change souvent d'accord toutes les 2-4 mesures. Debussy peut tenir un accord 8 mesures." },
  { q: "Pourquoi Debussy n'utilise pas la dominante fonctionnelle ?", opts: ["Il ne connaissait pas cet accord","Il préfère la couleur harmonique à la tension-résolution fonctionnelle","La dominante est interdite en impressionnisme","Il utilisait uniquement la gamme pentatonique"], a: 1, fb: "Debussy recherche la couleur sonore pure — les accords comme textures plutôt que comme fonctions. La résolution V7→I crée une tension-résolution directionnelle qu'il trouve trop prévisible. Il lui préfère les glissements parallèles qui créent une impression, pas une direction." },
  { q: "La 'basse continue' baroque consiste en :", opts: ["Une ligne de basse contrapuntique complexe","Une ligne de basse chiffrée que le claveciniste/organiste réalise librement avec accords","Une basse en pizzicato des cordes","La basse qui joue le même rythme que la mélodie"], a: 1, fb: "La basse continue (basso continuo) est une ligne de basse chiffrée — des chiffres au-dessus des notes indiquent quels intervalles jouer. L'instrumentiste (clavecin, orgue, luth) réalise les accords librement à partir de ces chiffres. Fondamentale à la musique baroque." },
  { q: "Qu'est-ce qu'une 'relation de tierce' romantique ?", opts: ["Deux voix à distance de tierce","Mouvement de basse par tierce (ex. C→A♭, A♭→F) au lieu de quinte","Un accord de tierce augmentée","La résolution de la sensible vers la tonique"], a: 1, fb: "La relation de tierce est un mouvement harmonique par tierce entre fondamentales — typique du romantisme. CMaj → A♭Maj (tierce mineure) ou CMaj → EMaj (tierce majeure). Ces mouvements créent une surprise harmonique mais restent cohérents grâce aux notes communes." },
  { q: "La 'cadence évitée' chez Chopin signifie :", opts: ["Le V7 résout vers VI ou autre accord au lieu de I","On évite toute cadence dans les nocturnes","La pièce ne se termine pas","On évite l'accord V7"], a: 0, fb: "La cadence évitée (ou interrompue) : V7 ne résout pas vers I attendu mais vers VIm (ou autre accord). En C : G7→Am au lieu de G7→C. Chopin utilise fréquemment cette technique pour éviter la conclusion trop prévisible et maintenir la tension narrative." },
  // Compositeurs et œuvres
  { q: "Brahms disait entendre 'le pas de géants' derrière lui, désignant :", opts: ["Beethoven uniquement","Bach et Beethoven","Mozart et Haydn","Wagner et Liszt"], a: 1, fb: "Brahms était profondément intimidé par l'héritage de Bach (contrepoint) et Beethoven (structure symphonique). Il publie sa 1ère Symphonie à 43 ans seulement, après plus de 20 ans de travail. Sa synthèse de ces deux géants définit son style." },
  { q: "Quel album de Miles Davis (1959) est fondateur du jazz modal ?", opts: ["Kind of Blue","Bitches Brew","A Love Supreme","Giant Steps"], a: 0, fb: "Kind of Blue (1959) est l'album de jazz le plus vendu de tous les temps et le manifeste du jazz modal. Bill Evans et Wynton Kelly au piano. So What est en D dorien. Flamenco Sketches change de mode à chaque phrase. L'harmonie prime sur le bebop rapide." },
  { q: "Quelle pièce de Debussy illustre le mieux le parallélisme d'accords ?", opts: ["Arabesque n°1","La cathédrale engloutie","Für Elise","Le Lac des Cygnes"], a: 1, fb: "La cathédrale engloutie (Préludes, Livre I, n°10) de Debussy utilise des blocs d'accords de quintes parallèles évoquant les orgues d'une cathédrale sous l'eau. Les accords parallèles sans résolution sont la signature de cette pièce emblématique." },
  { q: "Brad Mehldau est connu pour ses réharmonisations jazz de :", opts: ["Bach et Haendel","Radiohead, Beatles et Nick Drake","Brahms et Schubert","Wagner et Liszt"], a: 1, fb: "Brad Mehldau (né 1970) réinterprète régulièrement des chansons de Radiohead (Exit Music, Paranoid Android), Beatles (Blackbird, Martha My Dear), et Nick Drake en jazz post-bop. Ses réharmonisations combinent improvisation jazz et sensibilité pop." },
  { q: "John Coltrane dans 'Giant Steps' (1960) utilise :", opts: ["Substitutions diatoniques uniquement","Cycle de tierces majeures divisant l'octave en 3 (Coltrane Changes)","Mode dorien exclusivement","La gamme par tons de Debussy"], a: 1, fb: "Giant Steps divise l'octave en trois tierces majeures égales : B – G – E♭ – B (Coltrane Changes). Chaque tonalité dure 2 beats. C'est une réharmonisation radicale du cycle de quintes — les musiciens de l'époque avaient du mal à improviser dessus à vitesse." },
  { q: "Chopin a passé la majeure partie de sa carrière à :", opts: ["Varsovie","Vienne","Paris","Londres"], a: 2, fb: "Frédéric Chopin (1810–1849) s'installe à Paris en 1831 et y passe la quasi-totalité de sa vie artistique, entouré des plus grands artistes romantiques (Liszt, Berlioz, Delacroix, George Sand). Paris était alors le centre de la vie musicale européenne." },
  { q: "Mozart compose ses trois symphonies les plus célèbres (n°39, 40, 41) :", opts: ["À 12 ans","En 1788, en 6 semaines","Dans ses premières années viennoises","À Salzburg sous Colloredo"], a: 1, fb: "Les symphonies n°39, 40 et 41 'Jupiter' sont composées à l'été 1788 en quelques semaines — un des exploits créatifs les plus stupéfiants de l'histoire de la musique. Mozart était alors en difficultés financières graves. Ces œuvres ne furent peut-être jamais jouées de son vivant." },
  { q: "Herbie Hancock dans 'Maiden Voyage' (1965) utilise des accords :", opts: ["De dominante classiques V7","Suspendus 7sus4 — sans tierce, approche quartalec","Parallèles de style Debussy","Du cycle de Coltrane Changes"], a: 1, fb: "Maiden Voyage utilise systématiquement des accords 7sus4 (quarte à la place de la tierce) — sans caractère majeur/mineur défini. Cette approche 'quartal' (par quartes) crée une ambiguïté modale proche de Debussy, une révolution dans le vocabulaire jazz." },
  { q: "Bach composait des chorals selon la pratique :", opts: ["Baroque italienne (bel canto)","SATB (Soprano Alto Ténor Basse) à 4 voix indépendantes","Romantique avec extensions","Impressionniste sans dominante"], a: 1, fb: "Les chorals de Bach sont écrits à 4 voix SATB. Chaque voix a son propre mouvement mélodique indépendant, sans quintes ni octaves parallèles. Ces chorals sont encore aujourd'hui le modèle pédagogique du contrepoint à 4 voix." },
  { q: "Quel pianiste romantique a le plus influencé le piano jazz moderne ?", opts: ["Liszt (technique virtuose)","Chopin (harmonies, emprunts modaux, texture)","Brahms (contrepoint)","Schubert (mélodie)"], a: 1, fb: "Chopin est l'influence pianistique la plus directe sur le jazz moderne. Bill Evans citait Chopin comme référence majeure pour ses voicings, ses emprunts modaux et sa texture arpégée. La parenté entre un nocturne de Chopin et un ballade d'Evans est frappante." },
  { q: "Que signifie 'musique impressionniste' en musique (par analogie à la peinture) ?", opts: ["Musique qui imite des sons de la nature","Musique qui crée une impression sensorielle par la couleur harmonique et le timbre, sans narration directionnelle","Musique peinte sur des tableaux","Musique pour accompagner des peintures"], a: 1, fb: "Comme les peintres impressionnistes capturent une impression de lumière (Monet, Renoir), Debussy et Ravel créent des 'impressions' sonores — La cathédrale engloutie, La Mer, Nuages. L'harmonie et le timbre priment sur la structure narrative." },
  // Distinguer styles proches
  { q: "Quelle est la principale différence entre Chopin et Debussy ?", opts: ["Chopin est plus ancien","Chopin utilise encore des dominantes fonctionnelles ; Debussy les évite","Debussy utilise plus d'emprunts modaux","Chopin compose uniquement pour orchestre"], a: 1, fb: "Chopin reste dans le cadre tonal — il résout ses V7 vers I, même s'il retarde, décore et emprunte. Debussy abandonne la résolution fonctionnelle — ses accords ne 'tombent' pas vers I, ils glissent en couleur. Cette différence est fondamentale." },
  { q: "Quelle est la différence de 'basse' entre Bach et Mozart ?", opts: ["Bach : octaves seules ; Mozart : accords seulement","Bach : basse continue mélodiquement active ; Mozart : Alberti bass répétitive","Bach : basse en pizzicato ; Mozart : arco","Aucune différence"], a: 1, fb: "La basse de Bach est une voix à part entière — elle fait contrepoint à la mélodie, avec son propre mouvement mélodique (descentes chromatiques, sauts expressifs). La basse d'Alberti de Mozart est une figure d'accompagnement répétitive qui soutient la mélodie sans l'égaler." },
  { q: "Jazz Evans vs Jazz Coltrane : principale différence harmonique ?", opts: ["Evans est plus rapide","Evans : voicings denses Maj7 et emprunts modaux ; Coltrane : cycle de tierces rapides (Coltrane Changes)","Coltrane utilise plus de pentatonique","Evans compose, Coltrane improvise uniquement"], a: 1, fb: "Bill Evans exploite les voicings riches en extensions (Maj9, Maj7#11) et les emprunts modaux. Coltrane dans Giant Steps utilise les 'Coltrane Changes' — cycle de tierces majeures qui change de tonalité toutes les 2 croches. Deux langages jazz distincts." },
  { q: "Rock modal vs Rock tonal : différence fondamentale ?", opts: ["Le rock tonal est plus rapide","Modal : pas de V7→I fonctionnel, progressions cycliques ; tonal : cadences parfaites V→I","Le rock modal utilise uniquement la gamme pentatonique","Le rock tonal est en mode mineur uniquement"], a: 1, fb: "Le rock tonal utilise les cadences fonctionnelles classiques (V7→I). Le rock modal évite délibérément le V7 — il lui substitue le ♭VII (mixolydien) ou laisse la progression cyclique sans résolution. I–♭VII–IV–I peut tourner indéfiniment." },
  { q: "Chopin vs Romantisme tardif (Rachmaninov) : différence de densité ?", opts: ["Aucune différence — même époque","Chopin : texture pianistique légère, emprunts ponctuels ; Rachmaninov : densité orchestrale maximale","Rachmaninov est plus simple","Chopin compose pour orchestre, Rachmaninov pour piano seul"], a: 1, fb: "Chopin est pianistique et intimiste — ses nocturnes ont 3-4 voix légères. Rachmaninov pense orchestralement — ses pièces pour piano ont la densité d'une partition orchestrale, avec de nombreuses voix, doublures et emprunts dramatiques permanents." },
  { q: "Quelle technique partage le style jazz Evans et le style Chopin ?", opts: ["La substitution tritonique","L'emprunt modal au mode mineur parallèle","La gamme par tons","La basse d'Alberti"], a: 1, fb: "Les deux utilisent l'emprunt modal au mode mineur parallèle. Chopin : IVm, ♭VI dans des progressions romantiques. Evans : CMaj7→Cm7→Fm7 dans Peace Piece. Cette parenté n'est pas un hasard — Evans citait Chopin comme influence majeure." },
  { q: "Quelle technique est UNIQUEMENT caractéristique du jazz parmi les styles étudiés ?", opts: ["L'emprunt modal","La substitution tritonique (V7 → ♭II7)","Les progressions par tierces","Les accords parallèles"], a: 1, fb: "La substitution tritonique est une invention du jazz bebop (années 1940). Elle n'existe pas dans la musique classique de Bach, Mozart, Chopin ou Debussy. Aucun des styles classiques ou rock ne l'utilise systématiquement." },
  { q: "La progression I–IV–V–I est caractéristique de quel(s) style(s) ?", opts: ["Uniquement Mozart","Bach et Mozart (mais pas Debussy ni jazz)","Tous les styles","Uniquement Bach"], a: 1, fb: "I–IV–V–I (cadence parfaite) est la progression tonale fondamentale — utilisée abondamment par Bach et Mozart. Chopin l'utilise mais enrichie (avec emprunts). Debussy l'évite. Le jazz la remplace par II–V–I. Le rock modal l'évite (pas de V7)." },
  { q: "Quel style utilise les 'doublures' (notes jouées en octaves simultanées) de façon systématique ?", opts: ["Jazz post-bop","Romantisme tardif (texture orchestrale dense)","Rock modal","Impressionnisme"], a: 1, fb: "Le romantisme tardif (Rachmaninov, Liszt) utilise les doublures en octaves — deux mains qui jouent la même mélodie à l'octave — pour atteindre une puissance orchestrale sur le piano. Cette technique est rarement utilisée dans le jazz ou l'impressionnisme." },
  { q: "Distinguer Bach (baroque) et Brahms (romantique) dans l'utilisation du contrepoint :", opts: ["Brahms n'utilise pas le contrepoint","Bach : fugue et contrepoint strict ; Brahms : contrepoint intégré à une texture romantique dense","Ils utilisent exactement le même type de contrepoint","Bach est plus harmonique que Brahms"], a: 1, fb: "Bach écrit des fugues avec contrepoint strict (invertible counterpoint, stretto). Brahms intègre le contrepoint à une texture romantique — ses œuvres ont des imitations, des canons, des lignes contrapuntiques, mais noyés dans une harmonie romantique riche." },
  { q: "Debussy et le jazz post-bop (Evans) partagent :", opts: ["Le cycle des quintes","Le parallélisme et l'évitement des dominantes fonctionnelles","La basse d'Alberti","Les cadences parfaites V→I"], a: 1, fb: "Les deux évitent les cadences V7→I et utilisent le parallélisme. Debussy : accords de 9e/Maj7 parallèles. Evans : blocs d'accords qui glissent, emprunts modaux. Cette parenté n'est pas un hasard — Evans était un grand lecteur de Debussy." },
  { q: "En style Mozart, l'harmonie est 'économe' car :", opts: ["Mozart n'avait pas d'accords complexes","Il utilise principalement I, IV, V7, IIm — peu d'accords différents par phrase","L'économie était une règle académique de l'époque","Il composait vite et n'avait pas le temps de complexifier"], a: 1, fb: "Mozart choisit délibérément la clarté harmonique — une phrase de 4 mesures peut n'utiliser que 3-4 accords. Cette économie n'est pas une limitation mais une esthétique : 'la perfection est atteinte quand il n'y a plus rien à enlever'." },
  // Reconnaissance de techniques
  { q: "On entend A♭Maj7 dans une progression en C majeur. C'est probablement :", opts: ["Un accord diatonique de C majeur","Un emprunt modal ♭VI (de C mineur)","Une substitution tritonique","Un accord de dominante secondaire"], a: 1, fb: "A♭Maj7 est ♭VI de C majeur — un accord emprunté à C mineur (naturel/éolien) où A♭ est le VIe degré naturel. C'est l'emprunt modal ♭VIMaj7, très utilisé dans le romantisme (Chopin, Rachmaninov) et le rock modal." },
  { q: "Dans une progression CMaj7–B♭Maj7–A♭Maj7, on reconnaît :", opts: ["Cycle des quintes descendant","Harmonisation parallèle Maj7 descendant par tons","Substitution tritonique","Emprunt de la gamme napolitaine"], a: 1, fb: "CMaj7→B♭Maj7→A♭Maj7 : chaque accord descend d'un ton entier, même structure Maj7 maintenue. C'est le parallélisme impressionniste. Aucune résolution de dominante, pas de fonction harmonique — pure couleur." },
  { q: "GMaj – FMaj – CMaj – GMaj en G : le F est :", opts: ["La quinte de C","Le ♭VII du mode mixolydien de G","Un emprunt napolitain","Un accord de sous-dominante en F majeur"], a: 1, fb: "En G majeur diatonique, la 7te est F# (pas F naturel). F naturel est la 7te mineure — c'est la note caractéristique du mode G mixolydien. L'accord FMaj est donc l'accord ♭VII mixolydien, emprunté au mode mixolydien." },
  { q: "Si on remplace G7 par D♭7 dans une progression en C, c'est :", opts: ["Un emprunt modal","Une substitution tritonique (rappel Cours 22)","Un accord napolitain","Une harmonisation parallèle"], a: 1, fb: "G7 → D♭7 est la substitution tritonique classique. G et D♭ sont à distance de triton (6 demi-tons). D♭7 résout vers C par mouvement de ½ ton (D♭→C), créant la basse chromatique D♭→C au lieu du saut de quinte G→C." },
  { q: "CMaj–Am–Dm–G7–CMaj : c'est :", opts: ["I–♭VI–♭II–♭VII–I","I–VIm–IIm–V7–I — cycle des quintes, style baroque/classique","I–♭VII–IV–V–I — mixolydien","Dm9–G13–CMaj9 — jazz avec extensions"], a: 1, fb: "I–VIm–IIm–V7–I est le cycle des quintes descendant fondamental. Chaque accord est à distance de quinte du précédent. C'est la progression de Bach et du classicisme. Cette 'ligne de basse' C→A→D→G→C forme le fondement du contrepoint baroque." },
  { q: "La note B♭ naturel dans une progression en G majeur indique :", opts: ["Une faute harmonique","Le mode G mixolydien (7te mineure ♭7)","Un accord napolitain","Une modulation en F majeur"], a: 1, fb: "En G majeur, B♭ n'existe pas (la 7te est B naturel). B♭ indique soit le mode G mixolydien (où la 7te est mineure), soit une modulation. Dans un contexte rock/modal, c'est presque toujours G mixolydien — la couleur rock par excellence." },
  { q: "Quel style utilise le plus les suspensions expressives (retards 4–3, 7–6) ?", opts: ["Debussy","Jazz bebop","Chopin et le romantisme","Bach baroque"], a: 2, fb: "Chopin et les romantiques utilisent fréquemment les suspensions (une note est retenue d'un accord à l'autre avant de résoudre). La suspension 4–3 (quarte qui résout vers tierce) est particulièrement expressive dans les nocturnes de Chopin." },
  { q: "Qu'est-ce qu'une 'note de passage chromatique' dans les voix intérieures ?", opts: ["Une note qui ne s'entend pas","Une note étrangère qui descend (ou monte) chromatiquement entre deux notes de l'accord","La fondamentale de l'accord","La note la plus haute de la voix de soprano"], a: 1, fb: "Une note de passage chromatique (ex. A♭ entre A et G dans la voix alto) glisse chromatiquement d'une note de l'accord à la suivante. Chopin en est maître — ses voix intérieures font de petits chromatismes expressifs qui ne s'entendent pas toujours consciemment mais enrichissent la texture." },
  { q: "La progression Am–G–F–G (en C majeur) est typique de :", opts: ["Style Chopin (emprunt modal)","Rock modal éolien (VI–♭VII–♭VI–♭VII cyclique)","Jazz II–V–I","Bach cycle des quintes"], a: 1, fb: "Am–G–F–G en C majeur = VIm–V–IV–V. En A éolien (ou C majeur modal), c'est la progression folk/rock éolienne — Stairway to Heaven (Led Zeppelin), Hotel California. Cyclique, sans dominante fonctionnelle, couleur modale naturelle." },
  { q: "Quel style combine le plus jazz et écriture pianistique classique ?", opts: ["Bebop traditionnel (Parker)","Jazz post-bop (Evans, Mehldau) — influences Debussy et Chopin","Rock modal","Neo-soul"], a: 1, fb: "Bill Evans et Brad Mehldau sont explicitement influencés par Debussy (parallélisme) et Chopin (emprunts modaux, texture arpégée). Evans a étudié de manière approfondie le répertoire de piano classique. Le jazz post-bop est la synthèse la plus directe entre jazz et piano classique." },
  { q: "La 'coda' d'une pièce romantique utilise souvent :", opts: ["Un retour soudain au premier thème","Une pédale de dominante longue avant la résolution finale","Un changement de tonalité vers le relatif majeur","Un motif exclusivement rythmique"], a: 1, fb: "La coda romantique utilise fréquemment la pédale de dominante (note V répétée en basse pendant que l'harmonie change au-dessus) pour créer une tension maximale avant la résolution finale. Rachmaninov et Tchaïkovski l'utilisent pour des finales dramatiques." },
  { q: "Quelle affirmation décrit le mieux le style de Brahms ?", opts: ["Moderniste et avant-gardiste","Contrepoint rigoureux dans une texture romantique dense — synthèse de Bach et Beethoven","Purement baroque, sans romantisme","Jazz et impressionnisme mélangés"], a: 1, fb: "Brahms est le 'conservateur romantique' — il maintient des structures classiques (contrepoint fugué, formes sonate rigoureuses) dans un langage harmonique romantique dense. Sa synthèse de Bach (contrepoint) et Beethoven (développement thématique) est unique." },
  { q: "Pourquoi la mélodie Do–Mi–Sol–Mi (arpège de C) peut-elle s'harmoniser dans presque tous les styles ?", opts: ["Parce qu'elle ne contient que 2 notes","Parce que C, E, G sont communes à de nombreux accords — CMaj, Am, Em, Fmaj7, A♭Maj7 (E=la 5te), etc.","Parce qu'elle est en mode dorien","Parce qu'elle est trop simple pour poser des contraintes"], a: 1, fb: "C, E, G sont présents dans CMaj, Am, Em, FMaj (C+E=3ce+5te), et même dans des accords de jazz (CMaj9, Am7, etc.). Cette flexibilité permet d'harmoniser cette mélodie dans n'importe quel style — c'est pourquoi on l'utilise comme mélodie-test pédagogique." },
];

const questionsEn: Question[] = [
  { q: "Which progression is characteristic of Bach's style?", opts: ["CMaj7–B♭Maj7–A♭Maj7 (parallelism)","CMaj–Am–Dm7–G7 (circle of fifths)","GMaj–FMaj–CMaj (Mixolydian)","Dm9–G13–CMaj9 (jazz extensions)"], a: 1, fb: "I–VIm–IIm–V7 is Bach's descending circle of fifths. Each chord is a fifth from the next. The G7→C resolution resolves the tritone B–F. This is the fundamental harmonic movement of Baroque counterpoint." },
  { q: "The Alberti bass (left hand: low–middle–high–middle) is characteristic of:", opts: ["Bach","Mozart","Chopin","Debussy"], a: 1, fb: "The Alberti bass is an accompanying figure characteristic of the Classical style (Mozart, Haydn). The left hand alternates bass–chord–middle–chord, creating a fluid and symmetrical accompaniment under the right-hand melody." },
  { q: "The IVm borrowing (e.g. Fm7 in C) in nocturnes is characteristic of:", opts: ["Bach","Mozart","Chopin","Debussy"], a: 2, fb: "Fm7 (IVm) in C major is Chopin's quintessential Romantic borrowing. He borrows IVm from the parallel minor (C minor), creating an unexpected dark color. This technique is rarely used by Bach or Mozart." },
  { q: "Parallel Maj7 chords without dominant resolution are characteristic of:", opts: ["Bach","Mozart","Chopin","Debussy"], a: 3, fb: "Debussy (impressionism) slides blocks of parallel chords — Maj7, 9th, quartal chords — without ever resolving to a dominant. Color takes precedence over harmonic function." },
  { q: "II–V–I with extensions (9th, 13th) and voicings without the fifth characterize:", opts: ["Modal rock","Post-bop jazz (Evans)","Romantic","Baroque (Bach)"], a: 1, fb: "Post-bop jazz (Bill Evans, Brad Mehldau) uses II–V–I enriched with extensions — 9th on II, 13th on V, 9th on I. Voicings omit the fifth (neutral) to keep 3rd, 7th, and coloring extensions." },
  { q: "I–♭VII–IV–I without functional dominant is the progression of:", opts: ["Chopin style","Baroque style","Modal rock (Mixolydian)","Jazz bebop"], a: 2, fb: "I–♭VII–IV–I is the quintessential modal rock progression. The ♭VII comes from the Mixolydian mode (minor seventh of the key). This progression can repeat indefinitely without V→I resolution — Norwegian Wood, Creep, Hey You." },
  { q: "Descending third relationships and dramatic minor borrowings characterize:", opts: ["Mozart style","Debussy style","Bach style","Late Romanticism (Rachmaninov)"], a: 3, fb: "Late Romanticism (Rachmaninov, Tchaikovsky) exploits third relationships (I→♭VI→IV) and dramatic minor borrowings. Harmonic density is maximum, with long dominant pedals." },
  { q: "Which style uses the most rigorous counterpoint?", opts: ["Jazz","Romantic","Bach (baroque)","Modal rock"], a: 2, fb: "Bach is the master of strict counterpoint. His rules: no parallel fifths, no parallel octaves, mandatory tritone resolution, inner voices with independent melodic movement. These rules define 4-voice counterpoint (SATB)." },
  { q: "Which style most avoids functional dominants V7→I?", opts: ["Debussy (impressionism)","Bach","Mozart","Jazz bebop"], a: 0, fb: "Debussy systematically avoids the V7→I resolution, which he finds too predictable. Instead, he slides parallel chords or uses whole-tone scales. This freedom from functional tonality is the signature of impressionism." },
  { q: "The 4+4 measure symmetry (antecedent + consequent) is characteristic of:", opts: ["Romantic","Modal jazz","Mozart (classical)","Debussy"], a: 2, fb: "The period form (4+4 measures) is the basic unit of the Viennese Classical style — Mozart, Haydn, early Beethoven. The antecedent (4 measures ending on V) is answered by the consequent (4 measures ending on I). Absolute symmetry and clarity." },
  { q: "The whole-tone scale (6 equidistant notes, no semitone) is associated with:", opts: ["Bach","Jazz bebop","Debussy","Modal rock"], a: 2, fb: "Debussy uses the whole-tone scale (C D E F# G# B♭) as a harmonic color. Without semitones, it creates an ambiguous floating sensation — no established tonal sense, no leading tone. This is one of the signatures of impressionism." },
  { q: "Tritone substitution (G7 → D♭7) is most used in:", opts: ["Bach style","Mozart style","Debussy style","Jazz (bebop/post-bop)"], a: 3, fb: "Tritone substitution is a jazz technique developed in bebop (1940s). It replaces V7 with the dominant chord a tritone lower, creating a descending chromatic bass (♭II→I)." },
  { q: "Cyclic progressions without final resolution are typical of:", opts: ["Bach","Mozart","Modal rock","Chopin"], a: 2, fb: "Modal rock uses cyclic progressions (I–♭VII–IV–I) that can repeat indefinitely. There is no need for a final V→I resolution. This is the big difference from classical tonal style." },
  { q: "Maximum harmonic density with many voices is characteristic of:", opts: ["Debussy","Mozart","Late Romanticism","Modal jazz"], a: 2, fb: "Rachmaninov and Tchaikovsky write orchestrally dense textures, with many doubled voices, rich chords, and generalized chromaticism. This is the apex of Romanticism — the complete opposite of Mozart's economy." },
  { q: "Which progression most clearly identifies a Debussy impressionist style?", opts: ["I–IV–V7–I","I–♭VI–IV–V","CMaj7–B♭Maj7–A♭Maj7–G♭Maj7","Dm9–G13–CMaj9"], a: 2, fb: "Four Maj7 chords descending by whole tones without resolution — this is Debussy's impressionist parallelism. No V7→I, no tension-resolution. Each chord is an autonomous color that 'slides' to the next." },
  { q: "Why does Bach avoid parallel fifths?", opts: ["They are too difficult to play","They create a 'hidden fifth' dissonance forbidden in strict counterpoint","They don't sound good on harpsichord","They were forbidden by the Church"], a: 1, fb: "Parallel fifths create a 'hidden fifth' in strict counterpoint — two voices move in the same direction and land on a fifth. This movement reduces voice independence, which is a fundamental rule of 4-voice counterpoint." },
  { q: "The 'descending circle of fifths' in C major gives:", opts: ["C – G – D – A – E – B – F# – C","C – F – Bdim – Em – Am – Dm – G – C","C – Am – Em – G – Dm – F – C","C – Dm – Em – F – G – Am – Bdim – C"], a: 1, fb: "The descending circle of fifths: C→F→B→E→A→D→G→C. In diatonic C major: CMaj – FMaj – Bdim – Em – Am – Dm – G7 – CMaj. Each chord descends a fifth (or rises a fourth). This is the fundamental harmonic progression of Baroque music." },
  { q: "How many notes does Debussy's whole-tone scale contain?", opts: ["5 (pentatonic)","6 (hexatonic)","7 (diatonic)","8 (octatonic)"], a: 1, fb: "The whole-tone scale is hexatonic — 6 notes equidistant by a whole tone: C D E F# G# B♭ (then back to C). The absence of a semitone gives it its characteristic tonal ambiguity. It is also called the 'Debussy scale'." },
  { q: "A jazz voicing 'without the fifth' omits the 5th because:", opts: ["The fifth is difficult to play","The perfect fifth is acoustically neutral and adds little color","The fifth doesn't exist in the pentatonic scale","The fifth creates a forbidden parallelism"], a: 1, fb: "The perfect fifth is acoustically the most consonant after the octave — it doesn't color the chord. In jazz, one keeps 3rd+7th (guide-tones) and adds 9th, 11th (#4), 13th. The fifth is often omitted to keep voicings tight and expressive." },
  { q: "The I–♭VII–IV–I progression is Mixolydian because:", opts: ["It contains 3 major chords","The ♭VII comes from the Mixolydian mode (minor seventh of the key)","It avoids the tonic","It descends by fifths"], a: 1, fb: "In G Mixolydian, the 7th is F natural (not F#). The chord built on this F natural is FMaj (♭VIIMaj) — a major chord foreign to G major but natural in G Mixolydian. This is the characteristic note distinguishing Mixolydian from Ionian." },
  { q: "A 'parallel mode borrowing' means:", opts: ["Borrowing from a neighboring key (fifth away)","Borrowing from the parallel mode (same tonic, different mode: C major ↔ C minor)","Borrowing from a pentatonic scale","Borrowing from a secondary dominant chord"], a: 1, fb: "Parallel mode borrowing uses chords from the key of the same name but different mode. In C major, borrowing Fm7 (IVm of C minor) is a parallel mode borrowing — same tonic C, but minor color." },
  { q: "'Fast' harmonic rhythm in jazz means:", opts: ["Fast tempo","2 chords per measure or more (vs 1 chord per 2–4 measures)","All chords are eighth notes","Many syncopations"], a: 1, fb: "Harmonic rhythm is the frequency of chord changes. In bebop/post-bop jazz, it is often fast: 2 chords per measure (or more in Coltrane Changes). Mozart often changes chord every 2–4 measures. Debussy can sustain a chord for 8 measures." },
  { q: "Why does Debussy not use the functional dominant?", opts: ["He didn't know this chord","He prefers harmonic color to functional tension-resolution","The dominant is forbidden in impressionism","He only used the pentatonic scale"], a: 1, fb: "Debussy seeks pure sonic color — chords as textures rather than functions. The V7→I resolution creates directional tension-resolution he finds too predictable. He prefers parallel sliding which creates an impression, not a direction." },
  { q: "The Baroque 'basso continuo' consists of:", opts: ["A complex contrapuntal bass line","A figured bass line that the harpsichordist/organist realizes freely with chords","A pizzicato bass from the strings","The bass playing the same rhythm as the melody"], a: 1, fb: "The basso continuo is a figured bass line — numbers above the notes indicate which intervals to play. The instrumentalist (harpsichord, organ, lute) realizes the chords freely from these figures. Fundamental to Baroque music." },
  { q: "What is a Romantic 'third relationship'?", opts: ["Two voices a third apart","Harmonic movement by third between roots (e.g. C→A♭, A♭→F) instead of fifth","An augmented third chord","The resolution of the leading tone to the tonic"], a: 1, fb: "A third relationship is harmonic movement by third between roots — typical of Romanticism. CMaj → A♭Maj (minor third) or CMaj → EMaj (major third). These movements create harmonic surprise but remain coherent thanks to common notes." },
  { q: "The 'deceptive cadence' in Chopin means:", opts: ["V7 resolves to VI or another chord instead of I","All cadences are avoided in nocturnes","The piece doesn't end","The V7 chord is avoided"], a: 0, fb: "The deceptive (or interrupted) cadence: V7 doesn't resolve to the expected I but to VIm (or another chord). In C: G7→Am instead of G7→C. Chopin frequently uses this technique to avoid too predictable a conclusion and maintain narrative tension." },
  { q: "Brahms said he heard 'the footsteps of giants' behind him, referring to:", opts: ["Only Beethoven","Bach and Beethoven","Mozart and Haydn","Wagner and Liszt"], a: 1, fb: "Brahms was deeply intimidated by the legacy of Bach (counterpoint) and Beethoven (symphonic structure). He published his 1st Symphony at age 43 only, after more than 20 years of work. His synthesis of these two giants defines his style." },
  { q: "Which Miles Davis album (1959) is foundational for modal jazz?", opts: ["Kind of Blue","Bitches Brew","A Love Supreme","Giant Steps"], a: 0, fb: "Kind of Blue (1959) is the best-selling jazz album of all time and the manifesto of modal jazz. Bill Evans and Wynton Kelly on piano. So What is in D Dorian. Flamenco Sketches changes mode each phrase. Harmony takes precedence over fast bebop." },
  { q: "Which Debussy piece best illustrates chord parallelism?", opts: ["Arabesque No.1","La cathédrale engloutie","Für Elise","Swan Lake"], a: 1, fb: "La cathédrale engloutie (Préludes, Book I, No.10) by Debussy uses blocks of parallel fifth chords evoking the organs of an underwater cathedral. Parallel chords without resolution are the signature of this iconic piece." },
  { q: "Brad Mehldau is known for his jazz reharmonizations of:", opts: ["Bach and Handel","Radiohead, Beatles and Nick Drake","Brahms and Schubert","Wagner and Liszt"], a: 1, fb: "Brad Mehldau (born 1970) regularly reinterprets songs by Radiohead (Exit Music, Paranoid Android), Beatles (Blackbird, Martha My Dear), and Nick Drake in post-bop jazz. His reharmonizations combine jazz improvisation and pop sensitivity." },
  { q: "John Coltrane in 'Giant Steps' (1960) uses:", opts: ["Diatonic substitutions only","A cycle of major thirds dividing the octave into 3 equal parts (Coltrane Changes)","Dorian mode exclusively","Debussy's whole-tone scale"], a: 1, fb: "Giant Steps divides the octave into three equal major thirds: B – G – E♭ – B (Coltrane Changes). Each key lasts 2 beats. It is a radical reharmonization of the circle of fifths — musicians of the time struggled to improvise over it at tempo." },
  { q: "Chopin spent most of his career in:", opts: ["Warsaw","Vienna","Paris","London"], a: 2, fb: "Frédéric Chopin (1810–1849) settled in Paris in 1831 and spent virtually his entire artistic life there, surrounded by the greatest Romantic artists (Liszt, Berlioz, Delacroix, George Sand). Paris was then the center of European musical life." },
  { q: "Mozart composes his three most famous symphonies (No.39, 40, 41):", opts: ["At age 12","In 1788, in 6 weeks","In his early Viennese years","In Salzburg under Colloredo"], a: 1, fb: "Symphonies No.39, 40, and 41 'Jupiter' were composed in summer 1788 in a few weeks — one of the most stunning creative feats in music history. Mozart was then in serious financial difficulties. These works may never have been performed in his lifetime." },
  { q: "Herbie Hancock in 'Maiden Voyage' (1965) uses:", opts: ["Classic dominant V7 chords","Suspended 7sus4 chords — without third, quartal approach","Parallel Debussy-style chords","Coltrane Changes cycle"], a: 1, fb: "Maiden Voyage systematically uses 7sus4 chords (fourth instead of third) — without defined major/minor character. This 'quartal' approach (by fourths) creates modal ambiguity close to Debussy, a revolution in jazz vocabulary." },
  { q: "Bach composed chorales according to the practice of:", opts: ["Italian baroque (bel canto)","SATB (Soprano Alto Tenor Bass) in 4 independent voices","Romantic with extensions","Impressionist without dominant"], a: 1, fb: "Bach's chorales are written for 4 SATB voices. Each voice has its own independent melodic movement, without parallel fifths or octaves. These chorales are still today the pedagogical model for 4-voice counterpoint." },
  { q: "Which Romantic pianist most influenced modern jazz piano?", opts: ["Liszt (virtuosic technique)","Chopin (harmonies, modal borrowings, texture)","Brahms (counterpoint)","Schubert (melody)"], a: 1, fb: "Chopin is the most direct pianistic influence on modern jazz. Bill Evans cited Chopin as a major reference for his voicings, modal borrowings, and arpeggiated texture. The kinship between a Chopin nocturne and an Evans ballad is striking." },
  { q: "What does 'impressionist music' mean (by analogy with painting)?", opts: ["Music that imitates sounds of nature","Music that creates a sensory impression through harmonic color and timbre, without directional narrative","Music painted on canvases","Music to accompany paintings"], a: 1, fb: "Just as Impressionist painters capture an impression of light (Monet, Renoir), Debussy and Ravel create sonic 'impressions' — La cathédrale engloutie, La Mer, Nuages. Harmony and timbre take precedence over narrative structure." },
  { q: "What is the main difference between Chopin and Debussy?", opts: ["Chopin is older","Chopin still uses functional dominants; Debussy avoids them","Debussy uses more modal borrowings","Chopin composes only for orchestra"], a: 1, fb: "Chopin remains within the tonal framework — he resolves his V7 to I, even if delayed, decorated, and borrowed. Debussy abandons functional resolution — his chords don't 'fall' toward I, they slide in color. This difference is fundamental." },
  { q: "What is the 'bass' difference between Bach and Mozart?", opts: ["Bach: octaves only; Mozart: chords only","Bach: melodically active continuo bass; Mozart: repetitive Alberti bass","Bach: pizzicato bass; Mozart: arco","No difference"], a: 1, fb: "Bach's bass is a full voice — it counterpoints the melody, with its own melodic movement (chromatic descents, expressive leaps). Mozart's Alberti bass is a repetitive accompanying figure that supports the melody without equaling it." },
  { q: "Jazz Evans vs Jazz Coltrane: main harmonic difference?", opts: ["Evans is faster","Evans: dense Maj7 voicings and modal borrowings; Coltrane: fast major thirds cycle (Coltrane Changes)","Coltrane uses more pentatonic","Evans composes, Coltrane only improvises"], a: 1, fb: "Bill Evans exploits voicings rich in extensions (Maj9, Maj7#11) and modal borrowings. Coltrane in Giant Steps uses 'Coltrane Changes' — a cycle of major thirds that changes key every 2 eighth notes. Two distinct jazz languages." },
  { q: "Modal rock vs tonal rock: fundamental difference?", opts: ["Tonal rock is faster","Modal: no functional V7→I, cyclic progressions; tonal: perfect cadences V→I","Modal rock uses only pentatonic scale","Tonal rock is only in minor mode"], a: 1, fb: "Tonal rock uses classic functional cadences (V7→I). Modal rock deliberately avoids V7 — substituting ♭VII (Mixolydian) or leaving the cyclic progression without resolution. I–♭VII–IV–I can cycle indefinitely." },
  { q: "Chopin vs Late Romanticism (Rachmaninov): density difference?", opts: ["No difference — same era","Chopin: light pianistic texture, occasional borrowings; Rachmaninov: maximum orchestral density","Rachmaninov is simpler","Chopin composes for orchestra, Rachmaninov for solo piano"], a: 1, fb: "Chopin is pianistic and intimate — his nocturnes have 3–4 light voices. Rachmaninov thinks orchestrally — his piano pieces have the density of an orchestral score, with many voices, doublings, and permanent dramatic borrowings." },
  { q: "Which technique is shared by Evans jazz style and Chopin style?", opts: ["Tritone substitution","Modal borrowing from the parallel minor mode","Whole-tone scale","Alberti bass"], a: 1, fb: "Both use modal borrowing from the parallel minor. Chopin: IVm, ♭VI in Romantic progressions. Evans: CMaj7→Cm7→Fm7 in Peace Piece. This kinship is not coincidental — Evans cited Chopin as a major influence." },
  { q: "Which technique is ONLY characteristic of jazz among the studied styles?", opts: ["Modal borrowing","Tritone substitution (V7 → ♭II7)","Progressions by thirds","Parallel chords"], a: 1, fb: "Tritone substitution is a jazz bebop invention (1940s). It does not exist in the classical music of Bach, Mozart, Chopin, or Debussy. None of the classical or rock styles use it systematically." },
  { q: "The I–IV–V–I progression is characteristic of which style(s)?", opts: ["Only Mozart","Bach and Mozart (but not Debussy or jazz)","All styles","Only Bach"], a: 1, fb: "I–IV–V–I (perfect cadence) is the fundamental tonal progression — used abundantly by Bach and Mozart. Chopin uses it but enriched (with borrowings). Debussy avoids it. Jazz replaces it with II–V–I. Modal rock avoids it (no V7)." },
  { q: "Which style uses 'doublings' (notes played in simultaneous octaves) systematically?", opts: ["Post-bop jazz","Late Romanticism (dense orchestral texture)","Modal rock","Impressionism"], a: 1, fb: "Late Romanticism (Rachmaninov, Liszt) uses octave doublings — both hands playing the same melody an octave apart — to achieve orchestral power on the piano. This technique is rarely used in jazz or impressionism." },
  { q: "Distinguishing Bach (Baroque) and Brahms (Romantic) in their use of counterpoint:", opts: ["Brahms doesn't use counterpoint","Bach: fugue and strict counterpoint; Brahms: counterpoint integrated into dense Romantic texture","They use exactly the same type of counterpoint","Bach is more harmonic than Brahms"], a: 1, fb: "Bach writes fugues with strict counterpoint (invertible counterpoint, stretto). Brahms integrates counterpoint into a Romantic texture — his works have imitations, canons, contrapuntal lines, but immersed in rich Romantic harmony." },
  { q: "Debussy and post-bop jazz (Evans) share:", opts: ["The circle of fifths","Parallelism and avoidance of functional dominants","Alberti bass","Perfect cadences V→I"], a: 1, fb: "Both avoid V7→I cadences and use parallelism. Debussy: parallel 9th/Maj7 chords. Evans: sliding chord blocks, modal borrowings. This kinship is not coincidental — Evans was a keen reader of Debussy." },
  { q: "In Mozart's style, harmony is 'economical' because:", opts: ["Mozart had no complex chords","He mainly uses I, IV, V7, IIm — few different chords per phrase","Economy was an academic rule of the era","He composed fast and had no time to complexify"], a: 1, fb: "Mozart deliberately chooses harmonic clarity — a 4-measure phrase may use only 3–4 chords. This economy is not a limitation but an aesthetic: 'perfection is achieved when there is nothing more to remove'." },
  { q: "You hear A♭Maj7 in a C major progression. It is probably:", opts: ["A diatonic chord of C major","A modal borrowing ♭VI (from C minor)","A tritone substitution","A secondary dominant chord"], a: 1, fb: "A♭Maj7 is ♭VI of C major — a chord borrowed from C minor (natural/aeolian) where A♭ is the natural 6th degree. This is the modal borrowing ♭VIMaj7, widely used in Romanticism (Chopin, Rachmaninov) and modal rock." },
  { q: "In a progression CMaj7–B♭Maj7–A♭Maj7, one recognizes:", opts: ["Descending circle of fifths","Parallel Maj7 harmonization descending by whole tones","Tritone substitution","Borrowing from the Neapolitan scale"], a: 1, fb: "CMaj7→B♭Maj7→A♭Maj7: each chord descends by a whole tone, same Maj7 structure maintained. This is Debussy's impressionist parallelism. No dominant resolution, no harmonic function — pure color." },
  { q: "GMaj – FMaj – CMaj – GMaj in G: the F is:", opts: ["The fifth of C","The ♭VII of G Mixolydian mode","A Neapolitan borrowing","A subdominant chord in F major"], a: 1, fb: "In diatonic G major, the 7th is F# (not F natural). F natural is the minor 7th — the characteristic note of G Mixolydian mode. The FMaj chord is therefore the ♭VII Mixolydian chord, borrowed from Mixolydian mode." },
  { q: "If G7 is replaced by D♭7 in a C progression, this is:", opts: ["A modal borrowing","A tritone substitution (from Cours 22)","A Neapolitan chord","A parallel harmonization"], a: 1, fb: "G7 → D♭7 is the classic tritone substitution. G and D♭ are a tritone apart (6 semitones). D♭7 resolves to C by a half-step movement (D♭→C), creating the chromatic bass D♭→C instead of the fifth leap G→C." },
  { q: "CMaj–Am–Dm–G7–CMaj: this is:", opts: ["I–♭VI–♭II–♭VII–I","I–VIm–IIm–V7–I — circle of fifths, baroque/classical style","I–♭VII–IV–V–I — Mixolydian","Dm9–G13–CMaj9 — jazz with extensions"], a: 1, fb: "I–VIm–IIm–V7–I is the fundamental descending circle of fifths. Each chord is a fifth from the previous. This is the Bach and Classical progression. This 'bass line' C→A→D→G→C forms the foundation of Baroque counterpoint." },
  { q: "The note B♭ natural in a G major progression indicates:", opts: ["A harmonic error","G Mixolydian mode (minor 7th ♭7)","A Neapolitan chord","A modulation to F major"], a: 1, fb: "In G major, B♭ doesn't exist (the 7th is B natural). B♭ indicates either G Mixolydian mode (where the 7th is minor), or a modulation. In a rock/modal context, it is almost always G Mixolydian — the quintessential rock color." },
  { q: "Which style most uses expressive suspensions (retards 4–3, 7–6)?", opts: ["Debussy","Jazz bebop","Chopin and Romanticism","Baroque Bach"], a: 2, fb: "Chopin and the Romantics frequently use suspensions (a note is held from one chord to the next before resolving). The 4–3 suspension (fourth resolving to third) is particularly expressive in Chopin's nocturnes." },
  { q: "What is a 'chromatic passing note' in the inner voices?", opts: ["A note that cannot be heard","A foreign note that descends (or rises) chromatically between two notes of the chord","The root of the chord","The highest note of the soprano voice"], a: 1, fb: "A chromatic passing note (e.g. A♭ between A and G in the alto voice) slides chromatically from one chord note to the next. Chopin is a master of this — his inner voices have small expressive chromaticisms that enrich the texture." },
  { q: "The progression Am–G–F–G (in C major) is typical of:", opts: ["Chopin style (modal borrowing)","Modal Aeolian rock (VI–♭VII–♭VI–♭VII cyclic)","Jazz II–V–I","Bach circle of fifths"], a: 1, fb: "Am–G–F–G in C major = VIm–V–IV–V. In A Aeolian (or modal C major), this is the folk/rock Aeolian progression — Stairway to Heaven (Led Zeppelin), Hotel California. Cyclic, without functional dominant, natural modal color." },
  { q: "Which style most combines jazz and classical piano writing?", opts: ["Traditional bebop (Parker)","Post-bop jazz (Evans, Mehldau) — Debussy and Chopin influences","Modal rock","Neo-soul"], a: 1, fb: "Bill Evans and Brad Mehldau are explicitly influenced by Debussy (parallelism) and Chopin (modal borrowings, arpeggiated texture). Evans studied the classical piano repertoire extensively. Post-bop jazz is the most direct synthesis between jazz and classical piano." },
  { q: "The 'coda' of a Romantic piece often uses:", opts: ["A sudden return to the first theme","A long dominant pedal before the final resolution","A key change to the relative major","An exclusively rhythmic motif"], a: 1, fb: "The Romantic coda frequently uses the dominant pedal (note V repeated in the bass while the harmony changes above) to create maximum tension before the final resolution. Rachmaninov and Tchaikovsky use it for dramatic finales." },
  { q: "Which statement best describes Brahms's style?", opts: ["Modernist and avant-garde","Rigorous counterpoint in a dense Romantic texture — synthesis of Bach and Beethoven","Purely baroque, without Romanticism","Jazz and impressionism mixed"], a: 1, fb: "Brahms is the 'conservative Romantic' — he maintains classical structures (fugal counterpoint, rigorous sonata forms) in a dense Romantic harmonic language. His synthesis of Bach (counterpoint) and Beethoven (thematic development) is unique." },
  { q: "Why can the melody C–E–G–E (C arpeggio) be harmonized in almost any style?", opts: ["Because it only contains 2 notes","Because C, E, G are common to many chords — CMaj, Am, Em, Fmaj7, A♭Maj7 (E=the 5th), etc.","Because it is in Dorian mode","Because it is too simple to pose constraints"], a: 1, fb: "C, E, G are present in CMaj, Am, Em, FMaj (C+E = 3rd+5th), and even in jazz chords (CMaj9, Am7, etc.). This flexibility allows harmonizing this melody in any style — that's why it's used as a pedagogical test melody." },
];

const questionsEs: Question[] = [
  { q: "¿Qué progresión es característica del estilo de Bach?", opts: ["CMaj7–Si♭Maj7–La♭Maj7 (paralelismo)","DoMaj–Lam–Rem7–Sol7 (círculo de quintas)","SolMaj–FaMaj–DoMaj (mixolidio)","Rem9–Sol13–DoMaj9 (extensiones jazz)"], a: 1, fb: "I–VIm–IIm–V7 es el círculo de quintas descendente de Bach. Cada acorde está a distancia de quinta del siguiente. La resolución Sol7→Do resuelve el tritono Si–Fa. Es el movimiento armónico fundamental del contrapunto barroco." },
  { q: "El bajo de Alberti (mano izquierda: bajo–medio–alto–medio) es característico de:", opts: ["Bach","Mozart","Chopin","Debussy"], a: 1, fb: "El bajo de Alberti es una figura de acompañamiento característica del estilo clásico (Mozart, Haydn). La mano izquierda alterna bajo–acorde–medio–acorde, creando un acompañamiento fluido y simétrico bajo la melodía de la mano derecha." },
  { q: "El préstamo IVm (ej. Fam7 en Do) en los nocturnos es característico de:", opts: ["Bach","Mozart","Chopin","Debussy"], a: 2, fb: "Fam7 (IVm) en Do mayor es el préstamo romántico por excelencia de Chopin. Toma prestado el IVm del modo menor paralelo (Do menor), creando un color oscuro inesperado. Esta técnica es raramente utilizada por Bach o Mozart." },
  { q: "Los acordes Maj7 paralelos sin resolución de dominante son característicos de:", opts: ["Bach","Mozart","Chopin","Debussy"], a: 3, fb: "Debussy (impresionismo) hace deslizar bloques de acordes paralelos — Maj7, 9ª, acordes de cuartas — sin nunca resolver hacia una dominante. El color prima sobre la función armónica." },
  { q: "II–V–I con extensiones (9ª, 13ª) y voicings sin quinta caracterizan:", opts: ["Rock modal","Jazz post-bop (Evans)","Romántico","Barroco (Bach)"], a: 1, fb: "El jazz post-bop (Bill Evans, Brad Mehldau) usa II–V–I enriquecido con extensiones — 9ª en II, 13ª en V, 9ª en I. Los voicings omiten la quinta (neutra) para mantener 3ª, 7ª y extensiones colorantes." },
  { q: "I–♭VII–IV–I sin dominante funcional es la progresión del:", opts: ["Estilo Chopin","Estilo barroco","Rock modal (mixolidio)","Jazz bebop"], a: 2, fb: "I–♭VII–IV–I es la progresión del rock modal por excelencia. El ♭VII viene del modo mixolidio (7ª menor del tono). Esta progresión puede repetirse indefinidamente sin resolución V→I — Norwegian Wood, Creep, Hey You." },
  { q: "Las relaciones de terceras descendentes y préstamos dramáticos al menor caracterizan:", opts: ["Estilo Mozart","Estilo Debussy","Estilo Bach","Romanticismo tardío (Rachmaninov)"], a: 3, fb: "El romanticismo tardío (Rachmaninov, Tchaikovsky) explota las relaciones de terceras (I→♭VI→IV) y los préstamos dramáticos al menor. La densidad armónica es máxima, con largas pedales de dominante." },
  { q: "¿Qué estilo usa el contrapunto más riguroso?", opts: ["Jazz","Romántico","Bach (barroco)","Rock modal"], a: 2, fb: "Bach es el maestro del contrapunto estricto. Sus reglas: sin quintas paralelas, sin octavas paralelas, resolución obligatoria del tritono, voces interiores con movimiento melódico independiente. Estas reglas definen el contrapunto a 4 voces (SATB)." },
  { q: "¿Qué estilo evita más las dominantes funcionales V7→I?", opts: ["Debussy (impresionismo)","Bach","Mozart","Jazz bebop"], a: 0, fb: "Debussy evita sistemáticamente la resolución V7→I que encuentra demasiado predecible. En su lugar, hace deslizar acordes paralelos o usa escalas por tonos. Esta libertad frente a la tonalidad funcional es la firma del impresionismo." },
  { q: "La simetría de 4+4 compases (antecedente + consecuente) es característica de:", opts: ["Romántico","Jazz modal","Mozart (clásico)","Debussy"], a: 2, fb: "La forma período (4+4 compases) es la unidad básica del estilo clásico vienés — Mozart, Haydn, Beethoven joven. El antecedente (4 compases terminando en V) es respondido por el consecuente (4 compases terminando en I). Simetría y claridad absolutas." },
  { q: "La escala por tonos (6 notas equidistantes, sin semitonos) está asociada a:", opts: ["Bach","Jazz bebop","Debussy","Rock modal"], a: 2, fb: "Debussy usa la escala por tonos (C D E F# G# Si♭) como color armónico. Sin semitonos, crea una flotación ambigua — sin sentido tonal establecido, sin sensible. Es una de las firmas del impresionismo." },
  { q: "La sustitución de tritono (Sol7 → Re♭7) se usa principalmente en:", opts: ["Estilo Bach","Estilo Mozart","Estilo Debussy","Jazz (bebop/post-bop)"], a: 3, fb: "La sustitución de tritono es una técnica jazz desarrollada en el bebop (años 1940). Reemplaza V7 por el acorde de dominante situado un tritono más abajo, creando un bajo cromático descendente (♭II→I)." },
  { q: "Las progresiones cíclicas sin resolución final son típicas de:", opts: ["Bach","Mozart","Rock modal","Chopin"], a: 2, fb: "El rock modal usa progresiones cíclicas (I–♭VII–IV–I) que pueden repetirse indefinidamente. No hay necesidad de resolución final V→I. Esta es la gran diferencia con el estilo tonal clásico." },
  { q: "La densidad armónica máxima con numerosas voces es característica de:", opts: ["Debussy","Mozart","Romanticismo tardío","Jazz modal"], a: 2, fb: "Rachmaninov y Tchaikovsky escriben texturas orquestalmente densas, con numerosas voces dobladas, acordes ricos y cromatismo generalizado. Es el apogeo del romanticismo — todo lo contrario de la economía de Mozart." },
  { q: "¿Qué progresión identifica más claramente un estilo impresionista de Debussy?", opts: ["I–IV–V7–I","I–♭VI–IV–V","DoMaj7–Si♭Maj7–La♭Maj7–Sol♭Maj7","Rem9–Sol13–DoMaj9"], a: 2, fb: "Cuatro Maj7 descendiendo por tonos enteros sin resolución — es el paralelismo impresionista de Debussy. Sin V7→I, sin tensión-resolución. Cada acorde es un color autónomo que 'se desliza' hacia el siguiente." },
  { q: "¿Por qué Bach evita las quintas paralelas?", opts: ["Son demasiado difíciles de tocar","Crean una 'quinta oculta' prohibida en el contrapunto estricto","No suenan bien en el clavecín","Estaban prohibidas por la Iglesia"], a: 1, fb: "Las quintas paralelas crean una 'quinta oculta' en el contrapunto estricto — dos voces se mueven en la misma dirección y caen en una quinta. Este movimiento reduce la independencia de las voces, regla fundamental del contrapunto a 4 voces." },
  { q: "El 'círculo de quintas descendente' en Do mayor da:", opts: ["Do – Sol – Re – La – Mi – Si – Fa# – Do","Do – Fa – Sidim – Mim – Lam – Rem – Sol – Do","Do – Lam – Mim – Sol – Rem – Fa – Do","Do – Rem – Mim – Fa – Sol – Lam – Sidim – Do"], a: 1, fb: "El círculo de quintas descendente: Do→Fa→Si→Mi→La→Re→Sol→Do. En Do mayor diatónico: DoMaj – FaMaj – Sidim – Mim – Lam – Rem – Sol7 – DoMaj. Cada acorde desciende una quinta. Es la progresión armónica fundamental de la música barroca." },
  { q: "¿Cuántas notas contiene la escala por tonos de Debussy?", opts: ["5 (pentatónica)","6 (hexatónica)","7 (diatónica)","8 (octatónica)"], a: 1, fb: "La escala por tonos es hexatónica — 6 notas equidistantes un tono entero: C D E F# G# Si♭ (luego vuelve a C). La ausencia de semitono le da su característica ambigüedad tonal. También se llama 'escala de Debussy'." },
  { q: "Un voicing jazz 'sin quinta' omite la 5ª porque:", opts: ["La quinta es difícil de tocar","La quinta justa es acústicamente neutra y aporta poco color","La quinta no existe en la escala pentatónica","La quinta crea un paralelismo prohibido"], a: 1, fb: "La quinta justa es acústicamente la más consonante después de la octava — no colorea el acorde. En jazz, se mantiene 3ª+7ª (guide-tones) y se añade 9ª, 11ª (#4), 13ª. La quinta se omite a menudo para mantener voicings compactos y expresivos." },
  { q: "La progresión I–♭VII–IV–I es mixolidia porque:", opts: ["Contiene 3 acordes mayores","El ♭VII viene del modo mixolidio (7ª menor del tono)","Evita la tónica","Desciende por quintas"], a: 1, fb: "En Sol mixolidio, la 7ª es Fa natural (no Fa#). El acorde construido sobre este Fa natural es FaMaj (♭VIIMaj) — un acorde mayor ajeno a Sol mayor pero natural en Sol mixolidio. Es la nota característica que distingue mixolidio de jónico." },
  { q: "Un 'préstamo al modo paralelo' significa:", opts: ["Tomar prestado de una tonalidad vecina (a distancia de quinta)","Tomar prestado del modo paralelo (misma tónica, modo diferente: Do mayor ↔ Do menor)","Tomar prestado de una escala pentatónica","Tomar prestado de un acorde de dominante secundario"], a: 1, fb: "El préstamo al modo paralelo usa acordes de la tonalidad del mismo nombre pero de modo diferente. En Do mayor, tomar prestado Fam7 (IVm de Do menor) es un préstamo al modo paralelo — misma tónica Do, pero color menor." },
  { q: "El ritmo armónico 'rápido' en jazz significa:", opts: ["Tempo rápido","2 acordes por compás o más (vs 1 acorde por 2–4 compases)","Todos los acordes son corcheas","Muchas síncopas"], a: 1, fb: "El ritmo armónico es la frecuencia de los cambios de acordes. En el jazz bebop/post-bop, suele ser rápido: 2 acordes por compás (o más en los Coltrane Changes). Mozart cambia a menudo de acorde cada 2–4 compases. Debussy puede sostener un acorde 8 compases." },
  { q: "¿Por qué Debussy no usa la dominante funcional?", opts: ["No conocía ese acorde","Prefiere el color armónico a la tensión-resolución funcional","La dominante está prohibida en el impresionismo","Solo usaba la escala pentatónica"], a: 1, fb: "Debussy busca el color sonoro puro — los acordes como texturas en lugar de funciones. La resolución V7→I crea una tensión-resolución direccional que encuentra demasiado predecible. Prefiere los deslizamientos paralelos que crean una impresión, no una dirección." },
  { q: "El 'bajo continuo' barroco consiste en:", opts: ["Una línea de bajo contrapuntística compleja","Una línea de bajo cifrado que el clavecinista/organista realiza libremente con acordes","Un bajo en pizzicato de las cuerdas","El bajo que toca el mismo ritmo que la melodía"], a: 1, fb: "El bajo continuo es una línea de bajo cifrado — los números sobre las notas indican qué intervalos tocar. El instrumentista (clavecín, órgano, laúd) realiza los acordes libremente a partir de esos números. Fundamental en la música barroca." },
  { q: "¿Qué es una 'relación de tercera' romántica?", opts: ["Dos voces a distancia de tercera","Movimiento armónico por tercera entre fundamentales (ej. Do→La♭, La♭→Fa) en lugar de quinta","Un acorde de tercera aumentada","La resolución de la sensible hacia la tónica"], a: 1, fb: "La relación de tercera es un movimiento armónico por tercera entre fundamentales — típico del romanticismo. DoMaj → La♭Maj (tercera menor) o DoMaj → MiMaj (tercera mayor). Estos movimientos crean una sorpresa armónica pero mantienen coherencia gracias a las notas comunes." },
  { q: "La 'cadencia evitada' en Chopin significa:", opts: ["El V7 resuelve hacia VI u otro acorde en lugar de I","Se evitan todas las cadencias en los nocturnos","La pieza no termina","Se evita el acorde V7"], a: 0, fb: "La cadencia evitada (o interrumpida): V7 no resuelve hacia el esperado I sino hacia VIm (u otro acorde). En Do: Sol7→Lam en lugar de Sol7→Do. Chopin usa frecuentemente esta técnica para evitar la conclusión demasiado predecible y mantener la tensión narrativa." },
  { q: "Brahms decía escuchar 'el paso de gigantes' detrás de él, refiriéndose a:", opts: ["Solo Beethoven","Bach y Beethoven","Mozart y Haydn","Wagner y Liszt"], a: 1, fb: "Brahms estaba profundamente intimidado por el legado de Bach (contrapunto) y Beethoven (estructura sinfónica). Publicó su 1ª Sinfonía a los 43 años, tras más de 20 años de trabajo. Su síntesis de estos dos gigantes define su estilo." },
  { q: "¿Qué álbum de Miles Davis (1959) es fundador del jazz modal?", opts: ["Kind of Blue","Bitches Brew","A Love Supreme","Giant Steps"], a: 0, fb: "Kind of Blue (1959) es el álbum de jazz más vendido de todos los tiempos y el manifiesto del jazz modal. Bill Evans y Wynton Kelly al piano. So What está en Re dórico. Flamenco Sketches cambia de modo en cada frase." },
  { q: "¿Qué pieza de Debussy ilustra mejor el paralelismo de acordes?", opts: ["Arabesco n°1","La catedral sumergida","Für Elise","El lago de los cisnes"], a: 1, fb: "La catedral sumergida (Preludios, Libro I, n°10) de Debussy usa bloques de acordes de quintas paralelas evocando los órganos de una catedral bajo el agua. Los acordes paralelos sin resolución son la firma de esta pieza emblemática." },
  { q: "Brad Mehldau es conocido por sus rearmonizaciones jazz de:", opts: ["Bach y Haendel","Radiohead, Beatles y Nick Drake","Brahms y Schubert","Wagner y Liszt"], a: 1, fb: "Brad Mehldau (nacido en 1970) reinterpreta regularmente canciones de Radiohead (Exit Music, Paranoid Android), Beatles (Blackbird, Martha My Dear) y Nick Drake en jazz post-bop. Sus rearmonizaciones combinan improvisación jazz y sensibilidad pop." },
  { q: "John Coltrane en 'Giant Steps' (1960) utiliza:", opts: ["Solo sustituciones diatónicas","Un ciclo de terceras mayores que divide la octava en 3 partes iguales (Coltrane Changes)","Exclusivamente el modo dórico","La escala por tonos de Debussy"], a: 1, fb: "Giant Steps divide la octava en tres terceras mayores iguales: Si – Sol – Mi♭ – Si (Coltrane Changes). Cada tonalidad dura 2 tiempos. Es una rearmonización radical del círculo de quintas — los músicos de la época tenían dificultades para improvisar encima a tempo." },
  { q: "Chopin pasó la mayor parte de su carrera en:", opts: ["Varsovia","Viena","París","Londres"], a: 2, fb: "Frédéric Chopin (1810–1849) se instala en París en 1831 y pasa casi toda su vida artística allí, rodeado de los más grandes artistas románticos (Liszt, Berlioz, Delacroix, George Sand). París era entonces el centro de la vida musical europea." },
  { q: "Mozart compone sus tres sinfonías más célebres (n°39, 40, 41):", opts: ["A los 12 años","En 1788, en 6 semanas","En sus primeros años vieneses","En Salzburgo bajo Colloredo"], a: 1, fb: "Las sinfonías n°39, 40 y 41 'Júpiter' se componen en el verano de 1788 en pocas semanas — uno de los logros creativos más asombrosos de la historia de la música. Mozart estaba entonces en serias dificultades económicas." },
  { q: "Herbie Hancock en 'Maiden Voyage' (1965) usa acordes:", opts: ["De dominante clásicos V7","Suspendidos 7sus4 — sin tercera, enfoque cuartal","Paralelos al estilo de Debussy","Del ciclo Coltrane Changes"], a: 1, fb: "Maiden Voyage usa sistemáticamente acordes 7sus4 (cuarta en lugar de tercera) — sin carácter mayor/menor definido. Este enfoque 'cuartal' (por cuartas) crea una ambigüedad modal próxima a Debussy, una revolución en el vocabulario jazz." },
  { q: "Bach componía corales según la práctica:", opts: ["Barroca italiana (bel canto)","SATB (Soprano Alto Tenor Bajo) a 4 voces independientes","Romántica con extensiones","Impresionista sin dominante"], a: 1, fb: "Los corales de Bach están escritos a 4 voces SATB. Cada voz tiene su propio movimiento melódico independiente, sin quintas ni octavas paralelas. Estos corales son aún hoy el modelo pedagógico del contrapunto a 4 voces." },
  { q: "¿Qué pianista romántico influyó más en el piano jazz moderno?", opts: ["Liszt (técnica virtuosa)","Chopin (armonías, préstamos modales, textura)","Brahms (contrapunto)","Schubert (melodía)"], a: 1, fb: "Chopin es la influencia pianística más directa en el jazz moderno. Bill Evans citaba a Chopin como referencia mayor para sus voicings, sus préstamos modales y su textura arpegiada. El parentesco entre un nocturno de Chopin y una balada de Evans es llamativo." },
  { q: "¿Qué significa 'música impresionista' en música (por analogía con la pintura)?", opts: ["Música que imita sonidos de la naturaleza","Música que crea una impresión sensorial mediante el color armónico y el timbre, sin narración direccional","Música pintada sobre cuadros","Música para acompañar pinturas"], a: 1, fb: "Así como los pintores impresionistas capturan una impresión de luz (Monet, Renoir), Debussy y Ravel crean 'impresiones' sonoras — La catedral sumergida, El mar, Nubes. La armonía y el timbre priman sobre la estructura narrativa." },
  { q: "¿Cuál es la principal diferencia entre Chopin y Debussy?", opts: ["Chopin es más antiguo","Chopin usa aún dominantes funcionales; Debussy las evita","Debussy usa más préstamos modales","Chopin compone solo para orquesta"], a: 1, fb: "Chopin se mantiene en el marco tonal — resuelve sus V7 hacia I, aunque retrase, decore y tome prestado. Debussy abandona la resolución funcional — sus acordes no 'caen' hacia I, se deslizan en color. Esta diferencia es fundamental." },
  { q: "¿Cuál es la diferencia de 'bajo' entre Bach y Mozart?", opts: ["Bach: octavas solas; Mozart: solo acordes","Bach: bajo continuo melódicamente activo; Mozart: bajo de Alberti repetitivo","Bach: bajo en pizzicato; Mozart: arco","Ninguna diferencia"], a: 1, fb: "El bajo de Bach es una voz propia — hace contrapunto con la melodía, con su propio movimiento melódico (descensos cromáticos, saltos expresivos). El bajo de Alberti de Mozart es una figura de acompañamiento repetitiva que apoya la melodía sin igualarla." },
  { q: "Jazz Evans vs Jazz Coltrane: ¿principal diferencia armónica?", opts: ["Evans es más rápido","Evans: voicings densos Maj7 y préstamos modales; Coltrane: ciclo de terceras rápido (Coltrane Changes)","Coltrane usa más pentatónica","Evans compone, Coltrane improvisa únicamente"], a: 1, fb: "Bill Evans explota los voicings ricos en extensiones (Maj9, Maj7#11) y los préstamos modales. Coltrane en Giant Steps usa los 'Coltrane Changes' — ciclo de terceras mayores que cambia de tonalidad cada 2 corcheas. Dos lenguajes jazz distintos." },
  { q: "Rock modal vs rock tonal: ¿diferencia fundamental?", opts: ["El rock tonal es más rápido","Modal: sin V7→I funcional, progresiones cíclicas; tonal: cadencias perfectas V→I","El rock modal usa solo la escala pentatónica","El rock tonal es solo en modo menor"], a: 1, fb: "El rock tonal usa las cadencias funcionales clásicas (V7→I). El rock modal evita deliberadamente el V7 — le sustituye el ♭VII (mixolidio) o deja la progresión cíclica sin resolución. I–♭VII–IV–I puede girar indefinidamente." },
  { q: "Chopin vs Romanticismo tardío (Rachmaninov): ¿diferencia de densidad?", opts: ["Ninguna diferencia — misma época","Chopin: textura pianística ligera, préstamos puntuales; Rachmaninov: densidad orquestal máxima","Rachmaninov es más simple","Chopin compone para orquesta, Rachmaninov para piano solo"], a: 1, fb: "Chopin es pianístico e íntimo — sus nocturnos tienen 3–4 voces ligeras. Rachmaninov piensa orquestalmente — sus piezas para piano tienen la densidad de una partitura orquestal, con numerosas voces, dobladuras y préstamos dramáticos permanentes." },
  { q: "¿Qué técnica comparten el estilo jazz Evans y el estilo Chopin?", opts: ["La sustitución de tritono","El préstamo modal al modo menor paralelo","La escala por tonos","El bajo de Alberti"], a: 1, fb: "Ambos usan el préstamo modal al modo menor paralelo. Chopin: IVm, ♭VI en progresiones románticas. Evans: DoMaj7→Dom7→Fam7 en Peace Piece. Este parentesco no es casualidad — Evans citaba a Chopin como influencia mayor." },
  { q: "¿Qué técnica es ÚNICAMENTE característica del jazz entre los estilos estudiados?", opts: ["El préstamo modal","La sustitución de tritono (V7 → ♭II7)","Las progresiones por terceras","Los acordes paralelos"], a: 1, fb: "La sustitución de tritono es una invención del jazz bebop (años 1940). No existe en la música clásica de Bach, Mozart, Chopin o Debussy. Ninguno de los estilos clásicos o rock la usa sistemáticamente." },
  { q: "¿La progresión I–IV–V–I es característica de qué estilo(s)?", opts: ["Solo Mozart","Bach y Mozart (pero no Debussy ni jazz)","Todos los estilos","Solo Bach"], a: 1, fb: "I–IV–V–I (cadencia perfecta) es la progresión tonal fundamental — usada abundantemente por Bach y Mozart. Chopin la usa pero enriquecida (con préstamos). Debussy la evita. El jazz la reemplaza por II–V–I. El rock modal la evita (sin V7)." },
  { q: "¿Qué estilo usa las 'dobladuras' (notas tocadas en octavas simultáneas) de forma sistemática?", opts: ["Jazz post-bop","Romanticismo tardío (textura orquestal densa)","Rock modal","Impresionismo"], a: 1, fb: "El romanticismo tardío (Rachmaninov, Liszt) usa las dobladuras en octavas — ambas manos que tocan la misma melodía a la octava — para alcanzar una potencia orquestal en el piano. Esta técnica es raramente usada en el jazz o el impresionismo." },
  { q: "Distinguir a Bach (barroco) y Brahms (romántico) en el uso del contrapunto:", opts: ["Brahms no usa el contrapunto","Bach: fuga y contrapunto estricto; Brahms: contrapunto integrado en una textura romántica densa","Usan exactamente el mismo tipo de contrapunto","Bach es más armónico que Brahms"], a: 1, fb: "Bach escribe fugas con contrapunto estricto (contrapunto invertible, estrecho). Brahms integra el contrapunto en una textura romántica — sus obras tienen imitaciones, cánones, líneas contrapuntísticas, pero inmersos en una armonía romántica rica." },
  { q: "Debussy y el jazz post-bop (Evans) comparten:", opts: ["El círculo de quintas","El paralelismo y la evitación de las dominantes funcionales","El bajo de Alberti","Las cadencias perfectas V→I"], a: 1, fb: "Ambos evitan las cadencias V7→I y usan el paralelismo. Debussy: acordes de 9ª/Maj7 paralelos. Evans: bloques de acordes que se deslizan, préstamos modales. Este parentesco no es casualidad — Evans era un gran lector de Debussy." },
  { q: "En el estilo Mozart, la armonía es 'económica' porque:", opts: ["Mozart no tenía acordes complejos","Usa principalmente I, IV, V7, IIm — pocos acordes diferentes por frase","La economía era una regla académica de la época","Componía rápido y no tenía tiempo de complejizar"], a: 1, fb: "Mozart elige deliberadamente la claridad armónica — una frase de 4 compases puede usar solo 3–4 acordes. Esta economía no es una limitación sino una estética: 'la perfección se alcanza cuando ya no hay nada que quitar'." },
  { q: "Se escucha La♭Maj7 en una progresión en Do mayor. Probablemente es:", opts: ["Un acorde diatónico de Do mayor","Un préstamo modal ♭VI (de Do menor)","Una sustitución de tritono","Un acorde de dominante secundario"], a: 1, fb: "La♭Maj7 es ♭VI de Do mayor — un acorde prestado de Do menor (natural/eólico) donde La♭ es el VI grado natural. Es el préstamo modal ♭VIMaj7, muy usado en el romanticismo (Chopin, Rachmaninov) y el rock modal." },
  { q: "En una progresión DoMaj7–Si♭Maj7–La♭Maj7, se reconoce:", opts: ["Círculo de quintas descendente","Armonización Maj7 paralela descendente por tonos","Sustitución de tritono","Préstamo de la escala napolitana"], a: 1, fb: "DoMaj7→Si♭Maj7→La♭Maj7: cada acorde desciende un tono entero, misma estructura Maj7 mantenida. Es el paralelismo impresionista. Sin resolución de dominante, sin función armónica — color puro." },
  { q: "SolMaj – FaMaj – DoMaj – SolMaj en Sol: el Fa es:", opts: ["La quinta de Do","El ♭VII del modo mixolidio de Sol","Un préstamo napolitano","Un acorde de subdominante en Fa mayor"], a: 1, fb: "En Sol mayor diatónico, la 7ª es Fa# (no Fa natural). Fa natural es la 7ª menor — la nota característica del modo Sol mixolidio. El acorde FaMaj es por tanto el acorde ♭VII mixolidio, prestado del modo mixolidio." },
  { q: "Si se reemplaza Sol7 por Re♭7 en una progresión en Do, es:", opts: ["Un préstamo modal","Una sustitución de tritono (del Curso 22)","Un acorde napolitano","Una armonización paralela"], a: 1, fb: "Sol7 → Re♭7 es la sustitución de tritono clásica. Sol y Re♭ están a distancia de tritono (6 semitonos). Re♭7 resuelve hacia Do por movimiento de ½ tono (Re♭→Do), creando el bajo cromático Re♭→Do en lugar del salto de quinta Sol→Do." },
  { q: "DoMaj–Lam–Rem–Sol7–DoMaj: es:", opts: ["I–♭VI–♭II–♭VII–I","I–VIm–IIm–V7–I — círculo de quintas, estilo barroco/clásico","I–♭VII–IV–V–I — mixolidio","Rem9–Sol13–DoMaj9 — jazz con extensiones"], a: 1, fb: "I–VIm–IIm–V7–I es el círculo de quintas descendente fundamental. Cada acorde está a distancia de quinta del anterior. Es la progresión de Bach y el clasicismo. Esta 'línea de bajo' Do→La→Re→Sol→Do forma el fundamento del contrapunto barroco." },
  { q: "La nota Si♭ natural en una progresión en Sol mayor indica:", opts: ["Un error armónico","El modo Sol mixolidio (7ª menor ♭7)","Un acorde napolitano","Una modulación a Fa mayor"], a: 1, fb: "En Sol mayor, Si♭ no existe (la 7ª es Si natural). Si♭ indica el modo Sol mixolidio (donde la 7ª es menor) o una modulación. En un contexto rock/modal, es casi siempre Sol mixolidio — el color rock por excelencia." },
  { q: "¿Qué estilo usa más las suspensiones expresivas (retardos 4–3, 7–6)?", opts: ["Debussy","Jazz bebop","Chopin y el romanticismo","Bach barroco"], a: 2, fb: "Chopin y los románticos usan frecuentemente las suspensiones (una nota es retenida de un acorde al siguiente antes de resolver). La suspensión 4–3 (cuarta que resuelve hacia la tercera) es particularmente expresiva en los nocturnos de Chopin." },
  { q: "¿Qué es una 'nota de paso cromática' en las voces interiores?", opts: ["Una nota que no se escucha","Una nota ajena que desciende (o sube) cromáticamente entre dos notas del acorde","La fundamental del acorde","La nota más alta de la voz de soprano"], a: 1, fb: "Una nota de paso cromática (ej. La♭ entre La y Sol en la voz de contralto) se desliza cromáticamente de una nota del acorde a la siguiente. Chopin es maestro en esto — sus voces interiores hacen pequeños cromatismos expresivos que enriquecen la textura." },
  { q: "La progresión Lam–Sol–Fa–Sol (en Do mayor) es típica de:", opts: ["Estilo Chopin (préstamo modal)","Rock modal eólico (VI–♭VII–♭VI–♭VII cíclico)","Jazz II–V–I","Bach círculo de quintas"], a: 1, fb: "Lam–Sol–Fa–Sol en Do mayor = VIm–V–IV–V. En La eólico (o Do mayor modal), es la progresión folk/rock eólica — Stairway to Heaven (Led Zeppelin), Hotel California. Cíclica, sin dominante funcional, color modal natural." },
  { q: "¿Qué estilo combina más el jazz y la escritura pianística clásica?", opts: ["Bebop tradicional (Parker)","Jazz post-bop (Evans, Mehldau) — influencias de Debussy y Chopin","Rock modal","Neo-soul"], a: 1, fb: "Bill Evans y Brad Mehldau están explícitamente influenciados por Debussy (paralelismo) y Chopin (préstamos modales, textura arpegiada). Evans estudió en profundidad el repertorio de piano clásico. El jazz post-bop es la síntesis más directa entre jazz y piano clásico." },
  { q: "La 'coda' de una pieza romántica usa a menudo:", opts: ["Un retorno súbito al primer tema","Una larga pedal de dominante antes de la resolución final","Un cambio de tonalidad hacia el relativo mayor","Un motivo exclusivamente rítmico"], a: 1, fb: "La coda romántica usa frecuentemente la pedal de dominante (nota V repetida en el bajo mientras la armonía cambia arriba) para crear una tensión máxima antes de la resolución final. Rachmaninov y Tchaikovsky la usan para finales dramáticos." },
  { q: "¿Qué afirmación describe mejor el estilo de Brahms?", opts: ["Modernista y vanguardista","Contrapunto riguroso en una textura romántica densa — síntesis de Bach y Beethoven","Puramente barroco, sin romanticismo","Jazz e impresionismo mezclados"], a: 1, fb: "Brahms es el 'conservador romántico' — mantiene estructuras clásicas (contrapunto fugado, formas sonata rigurosas) en un lenguaje armónico romántico denso. Su síntesis de Bach (contrapunto) y Beethoven (desarrollo temático) es única." },
  { q: "¿Por qué la melodía Do–Mi–Sol–Mi (arpegio de Do) puede armonizarse en casi todos los estilos?", opts: ["Porque contiene solo 2 notas","Porque Do, Mi, Sol son comunes a muchos acordes — DoMaj, Lam, Mim, FaMaj7, La♭Maj7 (Mi=la 5ª), etc.","Porque está en modo dórico","Porque es demasiado simple para plantear restricciones"], a: 1, fb: "Do, Mi, Sol están presentes en DoMaj, Lam, Mim, FaMaj (Do+Mi=3ª+5ª) e incluso en acordes de jazz (DoMaj9, Lam7, etc.). Esta flexibilidad permite armonizar esta melodía en cualquier estilo — por eso se usa como melodía de prueba pedagógica." },
];

const questionsDe: Question[] = [
  { q: "Welche Progression ist charakteristisch für Bachs Stil?", opts: ["CMaj7–B♭Maj7–A♭Maj7 (Parallelismus)","CMaj–Am–Dm7–G7 (Quintenzirkel)","GMaj–FMaj–CMaj (Mixolydisch)","Dm9–G13–CMaj9 (Jazz-Erweiterungen)"], a: 1, fb: "I–VIm–IIm–V7 ist Bachs absteigender Quintenzirkel. Jeder Akkord liegt eine Quinte vom nächsten entfernt. Die G7→C-Auflösung löst den Tritonus H–F auf. Dies ist die grundlegende harmonische Bewegung des barocken Kontrapunkts." },
  { q: "Der Alberti-Bass (linke Hand: tief–mittel–hoch–mittel) ist charakteristisch für:", opts: ["Bach","Mozart","Chopin","Debussy"], a: 1, fb: "Der Alberti-Bass ist eine Begleitfigur, charakteristisch für den klassischen Stil (Mozart, Haydn). Die linke Hand wechselt Bass–Akkord–Mitte–Akkord und schafft so eine fließende und symmetrische Begleitung unter der Melodie der rechten Hand." },
  { q: "Die IVm-Anleihe (z.B. Fm7 in C) in Nocturnes ist charakteristisch für:", opts: ["Bach","Mozart","Chopin","Debussy"], a: 2, fb: "Fm7 (IVm) in C-Dur ist Chopins romantische Anleihe par excellence. Er leiht IVm aus dem parallelen Moll (c-Moll) aus und erzeugt eine unerwartete dunkle Farbe. Diese Technik wird von Bach oder Mozart selten verwendet." },
  { q: "Parallele Maj7-Akkorde ohne Dominantauflösung sind charakteristisch für:", opts: ["Bach","Mozart","Chopin","Debussy"], a: 3, fb: "Debussy (Impressionismus) lässt Blöcke paralleler Akkorde — Maj7, Nonen, Quartenakkorde — gleiten, ohne je auf eine Dominante aufzulösen. Die Farbe hat Vorrang vor der harmonischen Funktion." },
  { q: "II–V–I mit Erweiterungen (9., 13.) und Voicings ohne Quinte charakterisieren:", opts: ["Modaler Rock","Post-Bop-Jazz (Evans)","Romantisch","Barock (Bach)"], a: 1, fb: "Post-Bop-Jazz (Bill Evans, Brad Mehldau) verwendet II–V–I, angereichert mit Erweiterungen — 9. auf II, 13. auf V, 9. auf I. Voicings lassen die Quinte (neutral) weg, um 3., 7. und farbgebende Erweiterungen zu behalten." },
  { q: "I–♭VII–IV–I ohne funktionale Dominante ist die Progression des:", opts: ["Chopin-Stils","Barock-Stils","Modalen Rock (Mixolydisch)","Jazz-Bebop"], a: 2, fb: "I–♭VII–IV–I ist die modalen Rock-Progression par excellence. Das ♭VII kommt aus dem Mixolydischen Modus (kleine Septime des Tons). Diese Progression kann sich unendlich wiederholen ohne V→I-Auflösung — Norwegian Wood, Creep, Hey You." },
  { q: "Absteigende Terzverwandtschaften und dramatische Mollanleihen charakterisieren:", opts: ["Mozart-Stil","Debussy-Stil","Bach-Stil","Spätromantik (Rachmaninow)"], a: 3, fb: "Die Spätromantik (Rachmaninow, Tschaikowski) nutzt Terzverwandtschaften (I→♭VI→IV) und dramatische Mollanleihen. Die harmonische Dichte ist maximal, mit langen Dominantpedalpunkten." },
  { q: "Welcher Stil verwendet den strengsten Kontrapunkt?", opts: ["Jazz","Romantisch","Bach (Barock)","Modaler Rock"], a: 2, fb: "Bach ist der Meister des strengen Kontrapunkts. Seine Regeln: keine Parallelquinten, keine Paralleloktaven, obligatorische Tritonusauflösung, Innenstimmen mit unabhängiger melodischer Bewegung. Diese Regeln definieren den 4-stimmigen Kontrapunkt (SATB)." },
  { q: "Welcher Stil vermeidet funktionale Dominanten V7→I am meisten?", opts: ["Debussy (Impressionismus)","Bach","Mozart","Jazz-Bebop"], a: 0, fb: "Debussy vermeidet systematisch die V7→I-Auflösung, die er zu vorhersehbar findet. Stattdessen lässt er parallele Akkorde gleiten oder verwendet Ganztonleitern. Diese Freiheit von der funktionalen Tonalität ist die Signatur des Impressionismus." },
  { q: "Die 4+4-Takt-Symmetrie (Antezedenz + Konsequenz) ist charakteristisch für:", opts: ["Romantisch","Modaler Jazz","Mozart (klassisch)","Debussy"], a: 2, fb: "Die Periodenform (4+4 Takte) ist die Grundeinheit des Wiener Klassikstils — Mozart, Haydn, früher Beethoven. Der Antezedenz (4 Takte auf V endend) wird vom Konsequenz beantwortet (4 Takte auf I endend). Absolute Symmetrie und Klarheit." },
  { q: "Die Ganztonleiter (6 äquidistante Töne, kein Halbton) ist assoziiert mit:", opts: ["Bach","Jazz-Bebop","Debussy","Modaler Rock"], a: 2, fb: "Debussy verwendet die Ganztonleiter (C D E F# G# B♭) als harmonische Farbe. Ohne Halbton erzeugt sie eine ambigue Schwerelosigkeit — kein etablierter Tonalsinn, kein Leitton. Dies ist eine der Signaturen des Impressionismus." },
  { q: "Tritonussubstitution (G7 → D♭7) wird am häufigsten verwendet in:", opts: ["Bach-Stil","Mozart-Stil","Debussy-Stil","Jazz (Bebop/Post-Bop)"], a: 3, fb: "Tritonussubstitution ist eine im Bebop (1940er) entwickelte Jazz-Technik. Sie ersetzt V7 durch den Dominantakkord einen Tritonus tiefer und erzeugt einen chromatisch absteigenden Bass (♭II→I)." },
  { q: "Zyklische Progressionen ohne Schlussauflösung sind typisch für:", opts: ["Bach","Mozart","Modaler Rock","Chopin"], a: 2, fb: "Modaler Rock verwendet zyklische Progressionen (I–♭VII–IV–I), die sich unendlich wiederholen können. Es besteht keine Notwendigkeit für eine abschließende V→I-Auflösung. Das ist der große Unterschied zum klassischen Tonalstil." },
  { q: "Maximale harmonische Dichte mit vielen Stimmen ist charakteristisch für:", opts: ["Debussy","Mozart","Spätromantik","Modaler Jazz"], a: 2, fb: "Rachmaninow und Tschaikowski schreiben orchestral dichte Texturen mit vielen gedoppelten Stimmen, reichen Akkorden und generalisierter Chromatik. Dies ist der Höhepunkt der Romantik — das genaue Gegenteil von Mozarts Ökonomie." },
  { q: "Welche Progression identifiziert am deutlichsten einen impressionistischen Debussy-Stil?", opts: ["I–IV–V7–I","I–♭VI–IV–V","CMaj7–B♭Maj7–A♭Maj7–G♭Maj7","Dm9–G13–CMaj9"], a: 2, fb: "Vier Maj7-Akkorde, die in Ganztönen absteigen, ohne Auflösung — das ist Debussys impressionistischer Parallelismus. Kein V7→I, keine Spannung-Auflösung. Jeder Akkord ist eine autonome Farbe, die zur nächsten 'gleitet'." },
  { q: "Warum vermeidet Bach Parallelquinten?", opts: ["Sie sind zu schwer zu spielen","Sie erzeugen eine verbotene 'versteckte Quinte' im strengen Kontrapunkt","Sie klingen nicht gut auf dem Cembalo","Sie waren von der Kirche verboten"], a: 1, fb: "Parallelquinten erzeugen eine 'versteckte Quinte' im strengen Kontrapunkt — zwei Stimmen bewegen sich in dieselbe Richtung und landen auf einer Quinte. Diese Bewegung reduziert die Stimmunabhängigkeit, eine Grundregel des 4-stimmigen Kontrapunkts." },
  { q: "Der 'absteigende Quintenzirkel' in C-Dur ergibt:", opts: ["C – G – D – A – E – H – F# – C","C – F – Hdim – Em – Am – Dm – G – C","C – Am – Em – G – Dm – F – C","C – Dm – Em – F – G – Am – Hdim – C"], a: 1, fb: "Der absteigende Quintenzirkel: C→F→H→E→A→D→G→C. In diatonisch C-Dur: CMaj – FMaj – Hdim – Em – Am – Dm – G7 – CMaj. Jeder Akkord steigt eine Quinte ab (oder eine Quarte auf). Dies ist die fundamentale harmonische Progression der Barockmusik." },
  { q: "Wie viele Töne enthält Debussys Ganztonleiter?", opts: ["5 (Pentatonik)","6 (Hexatonik)","7 (Diatonik)","8 (Oktatonik)"], a: 1, fb: "Die Ganztonleiter ist hexatonisch — 6 äquidistante Töne um einen Ganzton: C D E F# G# B♭ (dann zurück zu C). Das Fehlen eines Halbtons verleiht ihr ihre charakteristische tonale Ambiguität. Sie wird auch 'Debussy-Skala' genannt." },
  { q: "Ein Jazz-Voicing 'ohne Quinte' lässt die 5. weg, weil:", opts: ["Die Quinte schwer zu spielen ist","Die reine Quinte akustisch neutral ist und wenig Farbe liefert","Die Quinte in der Pentatonik nicht existiert","Die Quinte einen verbotenen Parallelismus erzeugt"], a: 1, fb: "Die reine Quinte ist akustisch nach der Oktave am konsonantesten — sie färbt den Akkord nicht. Im Jazz behält man 3.+7. (Guide-Tones) und fügt 9., 11. (#4), 13. hinzu. Die Quinte wird oft weggelassen, um die Voicings kompakt und ausdrucksstark zu halten." },
  { q: "Die Progression I–♭VII–IV–I ist Mixolydisch, weil:", opts: ["Sie 3 Durakkorde enthält","Das ♭VII aus dem Mixolydischen Modus stammt (kleine Septime des Tons)","Sie die Tonika vermeidet","Sie in Quinten absteigt"], a: 1, fb: "In G-Mixolydisch ist die Septime F natürlich (nicht F#). Der auf diesem F natural gebaute Akkord ist FMaj (♭VIIMaj) — ein Durakkord, der G-Dur fremd, aber G-Mixolydisch natürlich ist. Das ist die charakteristische Note, die Mixolydisch von Ionisch unterscheidet." },
  { q: "Eine 'Paralleltonart-Anleihe' bedeutet:", opts: ["Aus einer Nachbartonart ausleihen (Quintabstand)","Aus dem parallelen Modus ausleihen (gleiche Tonika, verschiedener Modus: C-Dur ↔ c-Moll)","Aus einer Pentatonik ausleihen","Aus einem Sekundärdominantakkord ausleihen"], a: 1, fb: "Paralleltonart-Anleihe verwendet Akkorde des gleichnamigen Tons in verschiedenem Modus. In C-Dur ist das Ausleihen von Fm7 (IVm von c-Moll) eine Paralleltonart-Anleihe — gleiche Tonika C, aber Mollfarbe." },
  { q: "'Schneller' harmonischer Rhythmus im Jazz bedeutet:", opts: ["Schnelles Tempo","2 Akkorde pro Takt oder mehr (vs. 1 Akkord pro 2–4 Takte)","Alle Akkorde sind Achtelnoten","Viele Synkopen"], a: 1, fb: "Harmonischer Rhythmus ist die Häufigkeit der Akkordwechsel. Im Bebop/Post-Bop-Jazz ist er oft schnell: 2 Akkorde pro Takt (oder mehr in den Coltrane Changes). Mozart wechselt oft jeden Akkord alle 2–4 Takte. Debussy kann einen Akkord 8 Takte halten." },
  { q: "Warum verwendet Debussy nicht die funktionale Dominante?", opts: ["Er kannte diesen Akkord nicht","Er bevorzugt harmonische Farbe gegenüber funktionaler Spannung-Auflösung","Die Dominante ist im Impressionismus verboten","Er verwendete nur die Pentatonik"], a: 1, fb: "Debussy sucht reine Klangfarbe — Akkorde als Texturen statt als Funktionen. Die V7→I-Auflösung erzeugt eine gerichtete Spannung-Auflösung, die er zu vorhersehbar findet. Er zieht das parallele Gleiten vor, das einen Eindruck erzeugt, keine Richtung." },
  { q: "Der Barock-'Basso continuo' besteht aus:", opts: ["Einer komplexen kontrapunktischen Basslinie","Einer bezifferten Basslinie, die der Cembalist/Organist frei mit Akkorden ausführt","Einem Pizzicato-Bass der Streicher","Dem Bass, der denselben Rhythmus wie die Melodie spielt"], a: 1, fb: "Der Basso continuo ist eine bezifferte Basslinie — Zahlen über den Noten zeigen an, welche Intervalle zu spielen sind. Der Instrumentalist (Cembalo, Orgel, Laute) führt die Akkorde frei aus diesen Zahlen aus. Grundlegend für die Barockmusik." },
  { q: "Was ist eine romantische 'Terzverwandtschaft'?", opts: ["Zwei Stimmen in Terzabstand","Harmonische Bewegung durch Terz zwischen Grundtönen (z.B. C→A♭, A♭→F) statt Quinte","Ein übermäßiger Terzakkord","Die Auflösung des Leittons zur Tonika"], a: 1, fb: "Terzverwandtschaft ist eine harmonische Bewegung durch Terz zwischen Grundtönen — typisch für die Romantik. CMaj → A♭Maj (kleine Terz) oder CMaj → EMaj (große Terz). Diese Bewegungen erzeugen harmonische Überraschung, bleiben aber kohärent dank gemeinsamer Noten." },
  { q: "Die 'Trugschluss-Kadenz' bei Chopin bedeutet:", opts: ["V7 löst zu VI oder einem anderen Akkord statt I auf","Alle Kadenzen werden in Nocturnes vermieden","Das Stück endet nicht","Der V7-Akkord wird vermieden"], a: 0, fb: "Der Trugschluss (oder unterbrochene Kadenz): V7 löst nicht zum erwarteten I, sondern zu VIm (oder einem anderen Akkord) auf. In C: G7→Am statt G7→C. Chopin verwendet diese Technik häufig, um eine zu vorhersehbare Schlussfolgerung zu vermeiden." },
  { q: "Brahms sagte, er höre 'die Schritte von Riesen' hinter sich, gemeint war:", opts: ["Nur Beethoven","Bach und Beethoven","Mozart und Haydn","Wagner und Liszt"], a: 1, fb: "Brahms war zutiefst eingeschüchtert durch das Erbe von Bach (Kontrapunkt) und Beethoven (symphonische Struktur). Er veröffentlichte seine 1. Sinfonie erst mit 43 Jahren, nach über 20 Jahren Arbeit. Seine Synthese dieser zwei Giganten definiert seinen Stil." },
  { q: "Welches Miles-Davis-Album (1959) ist grundlegend für den modalen Jazz?", opts: ["Kind of Blue","Bitches Brew","A Love Supreme","Giant Steps"], a: 0, fb: "Kind of Blue (1959) ist das meistverkaufte Jazzalbum aller Zeiten und das Manifest des modalen Jazz. Bill Evans und Wynton Kelly am Klavier. So What ist in D-Dorisch. Flamenco Sketches wechselt jeden Satz den Modus." },
  { q: "Welches Debussy-Stück illustriert Akkord-Parallelismus am besten?", opts: ["Arabesque Nr.1","La cathédrale engloutie","Für Elise","Schwanensee"], a: 1, fb: "La cathédrale engloutie (Préludes, Buch I, Nr.10) von Debussy verwendet Blöcke paralleler Quintakkorde, die an die Orgeln einer versunkenen Kathedrale erinnern. Parallele Akkorde ohne Auflösung sind die Signatur dieses emblematischen Stücks." },
  { q: "Brad Mehldau ist bekannt für seine Jazz-Reharmonisierungen von:", opts: ["Bach und Händel","Radiohead, Beatles und Nick Drake","Brahms und Schubert","Wagner und Liszt"], a: 1, fb: "Brad Mehldau (geb. 1970) reinterpretiert regelmäßig Songs von Radiohead (Exit Music, Paranoid Android), Beatles (Blackbird, Martha My Dear) und Nick Drake im Post-Bop-Jazz. Seine Reharmonisierungen verbinden Jazz-Improvisation und Pop-Sensibilität." },
  { q: "John Coltrane in 'Giant Steps' (1960) verwendet:", opts: ["Nur diatonische Substitutionen","Einen Zyklus großer Terzen, der die Oktave in 3 gleiche Teile teilt (Coltrane Changes)","Ausschließlich den Dorischen Modus","Debussys Ganztonleiter"], a: 1, fb: "Giant Steps teilt die Oktave in drei gleiche große Terzen: H – G – E♭ – H (Coltrane Changes). Jede Tonart dauert 2 Zählzeiten. Es ist eine radikale Reharmonisierung des Quintenzirkels — Musiker der damaligen Zeit hatten Mühe, in Tempo zu improvisieren." },
  { q: "Chopin verbrachte den Großteil seiner Karriere in:", opts: ["Warschau","Wien","Paris","London"], a: 2, fb: "Frédéric Chopin (1810–1849) ließ sich 1831 in Paris nieder und verbrachte dort praktisch sein gesamtes künstlerisches Leben, umgeben von den größten Romantikern (Liszt, Berlioz, Delacroix, George Sand). Paris war damals das Zentrum des europäischen Musiklebens." },
  { q: "Mozart komponiert seine drei berühmtesten Sinfonien (Nr.39, 40, 41):", opts: ["Mit 12 Jahren","1788, in 6 Wochen","In seinen frühen Wiener Jahren","In Salzburg unter Colloredo"], a: 1, fb: "Sinfonien Nr.39, 40 und 41 'Jupiter' werden im Sommer 1788 in wenigen Wochen komponiert — eine der erstaunlichsten schöpferischen Leistungen in der Musikgeschichte. Mozart befand sich damals in ernsthaften finanziellen Schwierigkeiten." },
  { q: "Herbie Hancock in 'Maiden Voyage' (1965) verwendet Akkorde:", opts: ["Klassische Dominanten V7","Suspendierte 7sus4 — ohne Terz, Quartenansatz","Parallele Akkorde im Debussy-Stil","Coltrane-Changes-Zyklus"], a: 1, fb: "Maiden Voyage verwendet systematisch 7sus4-Akkorde (Quarte statt Terz) — ohne definierten Dur/Moll-Charakter. Dieser 'Quarten'-Ansatz erzeugt modale Ambiguität nahe Debussy, eine Revolution im Jazz-Vokabular." },
  { q: "Bach komponierte Choräle gemäß der Praxis:", opts: ["Italienischer Barock (Belcanto)","SATB (Sopran Alto Tenor Bass) in 4 unabhängigen Stimmen","Romantisch mit Erweiterungen","Impressionistisch ohne Dominante"], a: 1, fb: "Bachs Choräle sind für 4 SATB-Stimmen geschrieben. Jede Stimme hat ihre eigene unabhängige melodische Bewegung, ohne Parallelquinten oder -oktaven. Diese Choräle sind noch heute das pädagogische Modell für 4-stimmigen Kontrapunkt." },
  { q: "Welcher Romantiker-Pianist hat das moderne Jazz-Klavier am meisten beeinflusst?", opts: ["Liszt (virtuose Technik)","Chopin (Harmonien, modale Anleihen, Textur)","Brahms (Kontrapunkt)","Schubert (Melodie)"], a: 1, fb: "Chopin ist der direkteste pianistische Einfluss auf den modernen Jazz. Bill Evans nannte Chopin als wichtige Referenz für seine Voicings, modalen Anleihen und arpeggierte Textur. Die Verwandtschaft zwischen einem Chopin-Nocturne und einer Evans-Ballade ist frappierend." },
  { q: "Was bedeutet 'impressionistische Musik' in der Musik (in Analogie zur Malerei)?", opts: ["Musik, die Naturklänge imitiert","Musik, die durch harmonische Farbe und Klangfarbe einen Sinneseindruck erzeugt, ohne gerichtete Narration","Auf Gemälden gemalte Musik","Musik zur Begleitung von Gemälden"], a: 1, fb: "So wie Impressionisten Lichteindrücke einfangen (Monet, Renoir), schaffen Debussy und Ravel Klang-'Eindrücke' — La cathédrale engloutie, La Mer, Nuages. Harmonie und Klangfarbe haben Vorrang vor der Erzählstruktur." },
  { q: "Was ist der Hauptunterschied zwischen Chopin und Debussy?", opts: ["Chopin ist älter","Chopin verwendet noch funktionale Dominanten; Debussy vermeidet sie","Debussy verwendet mehr modale Anleihen","Chopin komponiert nur für Orchester"], a: 1, fb: "Chopin bleibt im tonalen Rahmen — er löst seine V7 auf I auf, auch wenn er verzögert, verziert und ausleiht. Debussy verlässt die funktionale Auflösung — seine Akkorde 'fallen' nicht auf I, sie gleiten farblich. Dieser Unterschied ist grundlegend." },
  { q: "Was ist der 'Bass'-Unterschied zwischen Bach und Mozart?", opts: ["Bach: nur Oktaven; Mozart: nur Akkorde","Bach: melodisch aktiver Continuobass; Mozart: repetitiver Alberti-Bass","Bach: Pizzicato-Bass; Mozart: Arco","Kein Unterschied"], a: 1, fb: "Bachs Bass ist eine vollwertige Stimme — er kontrapunktiert die Melodie mit eigener melodischer Bewegung (chromatische Absteigers, ausdrucksstarke Sprünge). Mozarts Alberti-Bass ist eine repetitive Begleitfigur, die die Melodie unterstützt ohne sie zu ebenbürtigen." },
  { q: "Jazz Evans vs Jazz Coltrane: Hauptharmonischer Unterschied?", opts: ["Evans ist schneller","Evans: dichte Maj7-Voicings und modale Anleihen; Coltrane: schneller Großterzenzyklus (Coltrane Changes)","Coltrane verwendet mehr Pentatonik","Evans komponiert, Coltrane improvisiert nur"], a: 1, fb: "Bill Evans nutzt Voicings reich an Erweiterungen (Maj9, Maj7#11) und modale Anleihen. Coltrane in Giant Steps verwendet 'Coltrane Changes' — einen Großterzenzyklus, der die Tonart alle 2 Achtelnoten wechselt. Zwei distinkte Jazz-Sprachen." },
  { q: "Modaler Rock vs tonaler Rock: Grundlegender Unterschied?", opts: ["Tonaler Rock ist schneller","Modal: kein funktionales V7→I, zyklische Progressionen; tonal: perfekte Kadenzen V→I","Modaler Rock verwendet nur Pentatonik","Tonaler Rock ist nur in Moll"], a: 1, fb: "Tonaler Rock verwendet klassische funktionale Kadenzen (V7→I). Modaler Rock vermeidet bewusst V7 — er ersetzt es durch ♭VII (Mixolydisch) oder lässt die zyklische Progression ohne Auflösung. I–♭VII–IV–I kann sich endlos wiederholen." },
  { q: "Chopin vs Spätromantik (Rachmaninow): Dichteunterschied?", opts: ["Kein Unterschied — gleiche Epoche","Chopin: leichte pianistische Textur, gelegentliche Anleihen; Rachmaninow: maximale Orchesterdichte","Rachmaninow ist einfacher","Chopin komponiert für Orchester, Rachmaninow für Soloklavier"], a: 1, fb: "Chopin ist pianistisch und intim — seine Nocturnes haben 3–4 leichte Stimmen. Rachmaninow denkt orchestral — seine Klavierstücke haben die Dichte einer Orchesterpartitur mit vielen Stimmen, Doppelungen und permanenten dramatischen Anleihen." },
  { q: "Welche Technik teilen Evans-Jazz-Stil und Chopin-Stil?", opts: ["Tritonussubstitution","Modale Anleihe aus dem parallelen Moll-Modus","Ganztonleiter","Alberti-Bass"], a: 1, fb: "Beide verwenden modale Anleihen aus dem parallelen Moll. Chopin: IVm, ♭VI in romantischen Progressionen. Evans: CMaj7→Cm7→Fm7 in Peace Piece. Diese Verwandtschaft ist kein Zufall — Evans nannte Chopin als großen Einfluss." },
  { q: "Welche Technik ist NUR charakteristisch für Jazz unter den untersuchten Stilen?", opts: ["Modale Anleihe","Tritonussubstitution (V7 → ♭II7)","Progressionen durch Terzen","Parallele Akkorde"], a: 1, fb: "Tritonussubstitution ist eine Jazz-Bebop-Erfindung (1940er). Sie existiert nicht in der klassischen Musik von Bach, Mozart, Chopin oder Debussy. Keiner der klassischen oder Rock-Stile verwendet sie systematisch." },
  { q: "Die I–IV–V–I-Progression ist charakteristisch für welche(n) Stil(e)?", opts: ["Nur Mozart","Bach und Mozart (aber nicht Debussy oder Jazz)","Alle Stile","Nur Bach"], a: 1, fb: "I–IV–V–I (perfekte Kadenz) ist die fundamentale Tonalprogression — reichlich bei Bach und Mozart verwendet. Chopin verwendet sie, aber angereichert (mit Anleihen). Debussy vermeidet sie. Jazz ersetzt sie durch II–V–I. Modaler Rock vermeidet sie (kein V7)." },
  { q: "Welcher Stil verwendet 'Doppelungen' (in gleichzeitigen Oktaven gespielte Noten) systematisch?", opts: ["Post-Bop-Jazz","Spätromantik (dichte Orchestertextur)","Modaler Rock","Impressionismus"], a: 1, fb: "Die Spätromantik (Rachmaninow, Liszt) verwendet Oktavdoppelungen — beide Hände spielen dieselbe Melodie oktaviert — um orchestrale Kraft auf dem Klavier zu erreichen. Diese Technik wird im Jazz oder Impressionismus selten verwendet." },
  { q: "Bach (Barock) und Brahms (Romantik) in der Verwendung des Kontrapunkts unterscheiden:", opts: ["Brahms verwendet keinen Kontrapunkt","Bach: Fuge und strenger Kontrapunkt; Brahms: in dichte romantische Textur integrierter Kontrapunkt","Sie verwenden exakt denselben Kontrapunkttyp","Bach ist harmonischer als Brahms"], a: 1, fb: "Bach schreibt Fugen mit strengem Kontrapunkt (invertierbarer Kontrapunkt, Engführung). Brahms integriert Kontrapunkt in eine romantische Textur — seine Werke haben Imitationen, Kanons, kontrapunktische Linien, aber in reiche romantische Harmonie getaucht." },
  { q: "Debussy und Post-Bop-Jazz (Evans) teilen:", opts: ["Den Quintenzirkel","Parallelismus und Vermeidung funktionaler Dominanten","Alberti-Bass","Perfekte Kadenzen V→I"], a: 1, fb: "Beide vermeiden V7→I-Kadenzen und verwenden Parallelismus. Debussy: parallele Nonen-/Maj7-Akkorde. Evans: gleitende Akkordblöcke, modale Anleihen. Diese Verwandtschaft ist kein Zufall — Evans war ein eifriger Leser von Debussy." },
  { q: "Im Mozart-Stil ist die Harmonik 'sparsam', weil:", opts: ["Mozart keine komplexen Akkorde kannte","Er hauptsächlich I, IV, V7, IIm verwendet — wenige verschiedene Akkorde pro Phrase","Sparsamkeit eine akademische Regel der Epoche war","Er schnell komponierte und keine Zeit hatte zu komplexieren"], a: 1, fb: "Mozart wählt bewusst harmonische Klarheit — eine 4-taktige Phrase kann nur 3–4 Akkorde verwenden. Diese Sparsamkeit ist keine Einschränkung, sondern eine Ästhetik: 'Vollkommenheit ist erreicht, wenn es nichts mehr zu entfernen gibt'." },
  { q: "Sie hören A♭Maj7 in einer C-Dur-Progression. Es ist wahrscheinlich:", opts: ["Ein diatonischer Akkord von C-Dur","Eine modale Anleihe ♭VI (aus c-Moll)","Eine Tritonussubstitution","Ein Sekundärdominantakkord"], a: 1, fb: "A♭Maj7 ist ♭VI von C-Dur — ein aus c-Moll (natürlich/äolisch) ausgeliehener Akkord, wo A♭ der natürliche VI. Grad ist. Das ist die modale Anleihe ♭VIMaj7, häufig verwendet in der Romantik (Chopin, Rachmaninow) und im modalen Rock." },
  { q: "In einer Progression CMaj7–B♭Maj7–A♭Maj7 erkennt man:", opts: ["Absteigender Quintenzirkel","Parallele Maj7-Harmonisierung, in Ganztönen absteigend","Tritonussubstitution","Anleihe aus der Neapolitanischen Skala"], a: 1, fb: "CMaj7→B♭Maj7→A♭Maj7: jeder Akkord steigt um einen Ganzton ab, gleiche Maj7-Struktur beibehalten. Das ist Debussys impressionistischer Parallelismus. Keine Dominantauflösung, keine harmonische Funktion — reine Farbe." },
  { q: "GMaj – FMaj – CMaj – GMaj in G: Das F ist:", opts: ["Die Quinte von C","Das ♭VII des G-Mixolydischen Modus","Eine Neapolitanische Anleihe","Ein Subdominantakkord in F-Dur"], a: 1, fb: "In diatonisch G-Dur ist die Septime F# (nicht F natürlich). F natürlich ist die kleine Septime — die charakteristische Note des G-Mixolydischen Modus. Der FMaj-Akkord ist daher der ♭VII-Mixolydische Akkord, ausgeliehen aus dem Mixolydischen Modus." },
  { q: "Wenn G7 durch D♭7 in einer C-Progression ersetzt wird, ist das:", opts: ["Eine modale Anleihe","Eine Tritonussubstitution (aus Kurs 22)","Ein Neapolitanischer Akkord","Eine Parallelharmonisierung"], a: 1, fb: "G7 → D♭7 ist die klassische Tritonussubstitution. G und D♭ sind einen Tritonus entfernt (6 Halbtöne). D♭7 löst durch Halbtonbewegung (D♭→C) auf C auf und erzeugt den chromatischen Bass D♭→C statt des Quintsprungs G→C." },
  { q: "CMaj–Am–Dm–G7–CMaj: das ist:", opts: ["I–♭VI–♭II–♭VII–I","I–VIm–IIm–V7–I — Quintenzirkel, Barock-/Klassikstil","I–♭VII–IV–V–I — Mixolydisch","Dm9–G13–CMaj9 — Jazz mit Erweiterungen"], a: 1, fb: "I–VIm–IIm–V7–I ist der fundamentale absteigende Quintenzirkel. Jeder Akkord liegt eine Quinte vom vorherigen entfernt. Das ist Bachs und der Klassik-Progression. Diese 'Basslinie' C→A→D→G→C bildet das Fundament des barocken Kontrapunkts." },
  { q: "Die Note B♭ natural in einer G-Dur-Progression zeigt an:", opts: ["Einen harmonischen Fehler","G-Mixolydischen Modus (kleine Septime ♭7)","Einen neapolitanischen Akkord","Eine Modulation nach F-Dur"], a: 1, fb: "In G-Dur existiert B♭ nicht (die Septime ist H natürlich). B♭ zeigt entweder G-Mixolydischen Modus (wo die Septime klein ist) oder eine Modulation an. Im Rock/Modalen Kontext ist es fast immer G-Mixolydisch — die quintessenzielle Rockfarbe." },
  { q: "Welcher Stil verwendet expressive Vorhaltungen (Retardierungen 4–3, 7–6) am häufigsten?", opts: ["Debussy","Jazz-Bebop","Chopin und Romantik","Barocker Bach"], a: 2, fb: "Chopin und die Romantiker verwenden häufig Vorhaltungen (eine Note wird von einem Akkord zum nächsten gehalten, bevor sie auflöst). Die 4–3-Vorhaltung (Quarte, die zur Terz auflöst) ist in Chopins Nocturnes besonders ausdrucksstark." },
  { q: "Was ist ein 'chromatischer Durchgangston' in den Innenstimmen?", opts: ["Ein Ton, der nicht zu hören ist","Ein fremder Ton, der chromatisch zwischen zwei Tönen des Akkords absteigt (oder aufsteigt)","Der Grundton des Akkords","Die höchste Note der Sopranstimme"], a: 1, fb: "Ein chromatischer Durchgangston (z.B. A♭ zwischen A und G in der Altstimme) gleitet chromatisch von einem Akkordton zum nächsten. Chopin ist darin Meister — seine Innenstimmen haben kleine expressive Chromatiken, die die Textur bereichern." },
  { q: "Die Progression Am–G–F–G (in C-Dur) ist typisch für:", opts: ["Chopin-Stil (modale Anleihe)","Modaler äolischer Rock (VI–♭VII–♭VI–♭VII zyklisch)","Jazz II–V–I","Bach-Quintenzirkel"], a: 1, fb: "Am–G–F–G in C-Dur = VIm–V–IV–V. In A-Äolisch (oder modalem C-Dur) ist das die Folk/Rock-Äolische Progression — Stairway to Heaven (Led Zeppelin), Hotel California. Zyklisch, ohne funktionale Dominante, natürliche Modalfarbe." },
  { q: "Welcher Stil verbindet Jazz und klassisches Klavierschreiben am meisten?", opts: ["Traditioneller Bebop (Parker)","Post-Bop-Jazz (Evans, Mehldau) — Debussy- und Chopin-Einflüsse","Modaler Rock","Neo-Soul"], a: 1, fb: "Bill Evans und Brad Mehldau sind explizit von Debussy (Parallelismus) und Chopin (modale Anleihen, Arpeggiotextur) beeinflusst. Evans studierte das klassische Klavierrepertoire eingehend. Post-Bop-Jazz ist die direkteste Synthese zwischen Jazz und klassischem Klavier." },
  { q: "Die 'Coda' eines romantischen Stücks verwendet oft:", opts: ["Eine plötzliche Rückkehr zum ersten Thema","Einen langen Dominantpedalpunkt vor der Schlussauflösung","Einen Tonartenwechsel zum Durparallel","Ein ausschließlich rhythmisches Motiv"], a: 1, fb: "Die romantische Coda verwendet häufig den Dominantpedalpunkt (Note V wiederholt im Bass, während die Harmonie darüber wechselt), um maximale Spannung vor der Schlussauflösung zu erzeugen. Rachmaninow und Tschaikowski nutzen ihn für dramatische Finalen." },
  { q: "Welche Aussage beschreibt Brahms' Stil am besten?", opts: ["Modernistisch und avantgardistisch","Strenger Kontrapunkt in einer dichten romantischen Textur — Synthese von Bach und Beethoven","Rein barock, ohne Romantik","Jazz und Impressionismus gemischt"], a: 1, fb: "Brahms ist der 'konservative Romantiker' — er hält klassische Strukturen (Fugenkontrapunkt, strenge Sonatenformen) in einer dichten romantischen Harmoniesprache aufrecht. Seine Synthese von Bach (Kontrapunkt) und Beethoven (thematische Entwicklung) ist einzigartig." },
  { q: "Warum kann die Melodie C–E–G–E (C-Arpeggio) in fast jedem Stil harmonisiert werden?", opts: ["Weil sie nur 2 Noten enthält","Weil C, E, G vielen Akkorden gemeinsam sind — CMaj, Am, Em, Fmaj7, A♭Maj7 (E=die 5.), usw.","Weil sie im Dorischen Modus ist","Weil sie zu einfach ist, um Einschränkungen zu stellen"], a: 1, fb: "C, E, G kommen in CMaj, Am, Em, FMaj (C+E = 3.+5.) und sogar in Jazz-Akkorden (CMaj9, Am7 usw.) vor. Diese Flexibilität ermöglicht die Harmonisierung dieser Melodie in jedem Stil — deshalb wird sie als pädagogische Testmelodie verwendet." },
];

const questionsIt: Question[] = [
  { q: "Quale progressione è caratteristica dello stile di Bach?", opts: ["CMaj7–Si♭Maj7–La♭Maj7 (parallelismo)","DoMag–Lam–Rem7–Sol7 (circolo delle quinte)","SolMag–FaMag–DoMag (Misolidio)","Rem9–Sol13–DoMag9 (estensioni jazz)"], a: 1, fb: "I–VIm–IIm–V7 è il circolo delle quinte discendente di Bach. Ogni accordo è a distanza di quinta dal successivo. La risoluzione Sol7→Do risolve il tritono Si–Fa. È il movimento armonico fondamentale del contrappunto barocco." },
  { q: "Il basso di Alberti (mano sinistra: basso–centro–alto–centro) è caratteristico di:", opts: ["Bach","Mozart","Chopin","Debussy"], a: 1, fb: "Il basso di Alberti è una figura di accompagnamento caratteristica dello stile classico (Mozart, Haydn). La mano sinistra alterna basso–accordo–centro–accordo, creando un accompagnamento fluente e simmetrico sotto la melodia della mano destra." },
  { q: "Il prestito IVm (es. Fam7 in Do) nei notturni è caratteristico di:", opts: ["Bach","Mozart","Chopin","Debussy"], a: 2, fb: "Fam7 (IVm) in Do maggiore è il prestito romantico per eccellenza di Chopin. Prende in prestito il IVm dal modo minore parallelo (Do minore), creando un inaspettato colore scuro. Questa tecnica è raramente usata da Bach o Mozart." },
  { q: "Accordi Maj7 paralleli senza risoluzione di dominante sono caratteristici di:", opts: ["Bach","Mozart","Chopin","Debussy"], a: 3, fb: "Debussy (impressionismo) fa scorrere blocchi di accordi paralleli — Maj7, nona, accordi di quarte — senza mai risolvere su una dominante. Il colore ha la precedenza sulla funzione armonica." },
  { q: "II–V–I con estensioni (9ª, 13ª) e voicings senza quinta caratterizzano:", opts: ["Rock modale","Jazz post-bop (Evans)","Romantico","Barocco (Bach)"], a: 1, fb: "Il jazz post-bop (Bill Evans, Brad Mehldau) usa II–V–I arricchito con estensioni — 9ª su II, 13ª su V, 9ª su I. I voicings omettono la quinta (neutra) per mantenere 3ª, 7ª ed estensioni coloranti." },
  { q: "I–♭VII–IV–I senza dominante funzionale è la progressione del:", opts: ["Stile Chopin","Stile barocco","Rock modale (Misolidio)","Jazz bebop"], a: 2, fb: "I–♭VII–IV–I è la progressione del rock modale per eccellenza. Il ♭VII viene dal modo Misolidio (settima minore del tono). Questa progressione può ripetersi indefinitamente senza risoluzione V→I — Norwegian Wood, Creep, Hey You." },
  { q: "Le relazioni di terze discendenti e i prestiti drammatici al minore caratterizzano:", opts: ["Stile Mozart","Stile Debussy","Stile Bach","Tardo romanticismo (Rachmaninov)"], a: 3, fb: "Il tardo romanticismo (Rachmaninov, Tchaikovsky) sfrutta le relazioni di terza (I→♭VI→IV) e i prestiti drammatici al minore. La densità armonica è massima, con lunghe pedali di dominante." },
  { q: "Quale stile usa il contrappunto più rigoroso?", opts: ["Jazz","Romantico","Bach (barocco)","Rock modale"], a: 2, fb: "Bach è il maestro del contrappunto rigoroso. Le sue regole: niente quinte parallele, niente ottave parallele, risoluzione obbligatoria del tritono, voci interne con movimento melodico indipendente. Queste regole definiscono il contrappunto a 4 voci (SATB)." },
  { q: "Quale stile evita maggiormente le dominanti funzionali V7→I?", opts: ["Debussy (impressionismo)","Bach","Mozart","Jazz bebop"], a: 0, fb: "Debussy evita sistematicamente la risoluzione V7→I che trova troppo prevedibile. Invece fa scorrere accordi paralleli o usa scale per toni interi. Questa libertà dalla tonalità funzionale è la firma dell'impressionismo." },
  { q: "La simmetria di 4+4 battute (antecedente + conseguente) è caratteristica di:", opts: ["Romantico","Jazz modale","Mozart (classico)","Debussy"], a: 2, fb: "La forma periodo (4+4 battute) è l'unità di base dello stile classico viennese — Mozart, Haydn, Beethoven giovane. L'antecedente (4 battute che finiscono su V) è risposto dal conseguente (4 battute che finiscono su I). Simmetria e chiarezza assolute." },
  { q: "La scala per toni interi (6 note equidistanti, nessun semitono) è associata a:", opts: ["Bach","Jazz bebop","Debussy","Rock modale"], a: 2, fb: "Debussy usa la scala per toni interi (C D E F# G# Si♭) come colore armonico. Senza semitoni, crea una fluttuazione ambigua — nessun senso tonale stabilito, nessuna sensibile. È una delle firme dell'impressionismo." },
  { q: "La sostituzione di tritono (Sol7 → Re♭7) è usata principalmente nel:", opts: ["Stile Bach","Stile Mozart","Stile Debussy","Jazz (bebop/post-bop)"], a: 3, fb: "La sostituzione di tritono è una tecnica jazz sviluppata nel bebop (anni '40). Sostituisce V7 con l'accordo di dominante situato un tritono più in basso, creando un basso cromatico discendente (♭II→I)." },
  { q: "Le progressioni cicliche senza risoluzione finale sono tipiche del:", opts: ["Bach","Mozart","Rock modale","Chopin"], a: 2, fb: "Il rock modale usa progressioni cicliche (I–♭VII–IV–I) che possono ripetersi indefinitamente. Non c'è bisogno di una risoluzione finale V→I. Questa è la grande differenza con lo stile tonale classico." },
  { q: "La massima densità armonica con molte voci è caratteristica del:", opts: ["Debussy","Mozart","Tardo romanticismo","Jazz modale"], a: 2, fb: "Rachmaninov e Tchaikovsky scrivono texture orchestralmente dense, con molte voci raddoppiate, accordi ricchi e cromatismo generalizzato. È l'apice del romanticismo — l'esatto contrario dell'economia di Mozart." },
  { q: "Quale progressione identifica più chiaramente uno stile impressionista di Debussy?", opts: ["I–IV–V7–I","I–♭VI–IV–V","DoMag7–Si♭Mag7–La♭Mag7–Sol♭Mag7","Rem9–Sol13–DoMag9"], a: 2, fb: "Quattro Maj7 che discendono per toni interi senza risoluzione — è il parallelismo impressionista di Debussy. Nessun V7→I, nessuna tensione-risoluzione. Ogni accordo è un colore autonomo che 'scivola' verso il successivo." },
  { q: "Perché Bach evita le quinte parallele?", opts: ["Sono troppo difficili da suonare","Creano una 'quinta nascosta' vietata nel contrappunto rigoroso","Non suonano bene al clavicembalo","Erano vietate dalla Chiesa"], a: 1, fb: "Le quinte parallele creano una 'quinta nascosta' nel contrappunto rigoroso — due voci si muovono nella stessa direzione e atterrano su una quinta. Questo movimento riduce l'indipendenza delle voci, regola fondamentale del contrappunto a 4 voci." },
  { q: "Il 'circolo delle quinte discendente' in Do maggiore dà:", opts: ["Do – Sol – Re – La – Mi – Si – Fa# – Do","Do – Fa – Sidim – Mim – Lam – Rem – Sol – Do","Do – Lam – Mim – Sol – Rem – Fa – Do","Do – Rem – Mim – Fa – Sol – Lam – Sidim – Do"], a: 1, fb: "Il circolo delle quinte discendente: Do→Fa→Si→Mi→La→Re→Sol→Do. In Do maggiore diatonico: DoMag – FaMag – Sidim – Mim – Lam – Rem – Sol7 – DoMag. Ogni accordo scende di una quinta. È la progressione armonica fondamentale della musica barocca." },
  { q: "Quante note contiene la scala per toni interi di Debussy?", opts: ["5 (pentatonica)","6 (esetatonica)","7 (diatonica)","8 (ottatonica)"], a: 1, fb: "La scala per toni interi è esatonale — 6 note equidistanti di un tono intero: C D E F# G# Si♭ (poi ritorna a C). L'assenza di semitoni le conferisce la sua caratteristica ambiguità tonale. È anche chiamata 'scala di Debussy'." },
  { q: "Un voicing jazz 'senza quinta' omette la 5ª perché:", opts: ["La quinta è difficile da suonare","La quinta giusta è acusticamente neutra e aggiunge poco colore","La quinta non esiste nella scala pentatonica","La quinta crea un parallelismo vietato"], a: 1, fb: "La quinta giusta è acusticamente la più consonante dopo l'ottava — non colora l'accordo. Nel jazz si mantengono 3ª+7ª (guide-tones) e si aggiungono 9ª, 11ª (#4), 13ª. La quinta è spesso omessa per mantenere i voicings compatti ed espressivi." },
  { q: "La progressione I–♭VII–IV–I è misolidia perché:", opts: ["Contiene 3 accordi maggiori","Il ♭VII viene dal modo Misolidio (settima minore del tono)","Evita la tonica","Scende per quinte"], a: 1, fb: "In Sol Misolidio, la settima è Fa naturale (non Fa#). L'accordo costruito su questo Fa naturale è FaMag (♭VIIMag) — un accordo maggiore estraneo a Sol maggiore ma naturale in Sol Misolidio. È la nota caratteristica che distingue il Misolidio dallo Ionico." },
  { q: "Un 'prestito dal modo parallelo' significa:", opts: ["Prendere in prestito da una tonalità vicina (distanza di quinta)","Prendere in prestito dal modo parallelo (stessa tonica, modo diverso: Do maggiore ↔ Do minore)","Prendere in prestito da una scala pentatonica","Prendere in prestito da un accordo di dominante secondaria"], a: 1, fb: "Il prestito dal modo parallelo usa accordi della tonalità dello stesso nome ma di modo diverso. In Do maggiore, prendere in prestito Fam7 (IVm di Do minore) è un prestito dal modo parallelo — stessa tonica Do, ma colore minore." },
  { q: "Il ritmo armonico 'rapido' nel jazz significa:", opts: ["Tempo veloce","2 accordi per battuta o più (vs 1 accordo per 2–4 battute)","Tutti gli accordi sono crome","Molte sincopi"], a: 1, fb: "Il ritmo armonico è la frequenza dei cambi di accordo. Nel jazz bebop/post-bop, è spesso rapido: 2 accordi per battuta (o più nei Coltrane Changes). Mozart cambia spesso accordo ogni 2–4 battute. Debussy può tenere un accordo 8 battute." },
  { q: "Perché Debussy non usa la dominante funzionale?", opts: ["Non conosceva questo accordo","Preferisce il colore armonico alla tensione-risoluzione funzionale","La dominante è vietata nell'impressionismo","Usava solo la scala pentatonica"], a: 1, fb: "Debussy cerca il puro colore sonoro — gli accordi come texture piuttosto che funzioni. La risoluzione V7→I crea una tensione-risoluzione direzionale che trova troppo prevedibile. Preferisce i scivolamenti paralleli che creano un'impressione, non una direzione." },
  { q: "Il 'basso continuo' barocco consiste in:", opts: ["Una linea di basso contrappuntistica complessa","Una linea di basso cifrata che il clavicembalista/organista realizza liberamente con accordi","Un basso in pizzicato degli archi","Il basso che suona lo stesso ritmo della melodia"], a: 1, fb: "Il basso continuo è una linea di basso cifrata — i numeri sopra le note indicano quali intervalli suonare. Lo strumentista (clavicembalo, organo, liuto) realizza gli accordi liberamente da questi numeri. Fondamentale per la musica barocca." },
  { q: "Cos'è una 'relazione di terza' romantica?", opts: ["Due voci a distanza di terza","Movimento armonico per terza tra fondamentali (es. Do→La♭, La♭→Fa) invece che per quinta","Un accordo di terza aumentata","La risoluzione della sensibile alla tonica"], a: 1, fb: "La relazione di terza è un movimento armonico per terza tra fondamentali — tipico del romanticismo. DoMag → La♭Mag (terza minore) o DoMag → MiMag (terza maggiore). Questi movimenti creano sorpresa armonica ma rimangono coerenti grazie alle note comuni." },
  { q: "La 'cadenza evitata' in Chopin significa:", opts: ["Il V7 risolve verso VI o un altro accordo invece di I","Si evitano tutte le cadenze nei notturni","Il brano non finisce","Si evita l'accordo V7"], a: 0, fb: "La cadenza evitata (o interrotta): V7 non risolve verso il previsto I ma verso VIm (o un altro accordo). In Do: Sol7→Lam invece di Sol7→Do. Chopin usa frequentemente questa tecnica per evitare una conclusione troppo prevedibile e mantenere la tensione narrativa." },
  { q: "Brahms diceva di sentire 'il passo dei giganti' dietro di lui, riferendosi a:", opts: ["Solo Beethoven","Bach e Beethoven","Mozart e Haydn","Wagner e Liszt"], a: 1, fb: "Brahms era profondamente intimidito dall'eredità di Bach (contrappunto) e Beethoven (struttura sinfonica). Pubblicò la sua 1ª Sinfonia solo a 43 anni, dopo più di 20 anni di lavoro. La sua sintesi di questi due giganti definisce il suo stile." },
  { q: "Quale album di Miles Davis (1959) è fondativo per il jazz modale?", opts: ["Kind of Blue","Bitches Brew","A Love Supreme","Giant Steps"], a: 0, fb: "Kind of Blue (1959) è l'album jazz più venduto di tutti i tempi e il manifesto del jazz modale. Bill Evans e Wynton Kelly al pianoforte. So What è in Re dorico. Flamenco Sketches cambia modo ad ogni frase." },
  { q: "Quale brano di Debussy illustra meglio il parallelismo degli accordi?", opts: ["Arabesco n°1","La cattedrale sommersa","Für Elise","Il lago dei cigni"], a: 1, fb: "La cattedrale sommersa (Preludi, Libro I, n°10) di Debussy usa blocchi di accordi di quinte parallele che evocano le organi di una cattedrale sott'acqua. Gli accordi paralleli senza risoluzione sono la firma di questo brano emblematico." },
  { q: "Brad Mehldau è noto per le sue riarmonizzazioni jazz di:", opts: ["Bach e Haendel","Radiohead, Beatles e Nick Drake","Brahms e Schubert","Wagner e Liszt"], a: 1, fb: "Brad Mehldau (nato nel 1970) reinterpreta regolarmente canzoni di Radiohead (Exit Music, Paranoid Android), Beatles (Blackbird, Martha My Dear) e Nick Drake in jazz post-bop. Le sue riarmonizzazioni combinano improvvisazione jazz e sensibilità pop." },
  { q: "John Coltrane in 'Giant Steps' (1960) usa:", opts: ["Solo sostituzioni diatoniche","Un ciclo di terze maggiori che divide l'ottava in 3 parti uguali (Coltrane Changes)","Esclusivamente il modo dorico","La scala per toni interi di Debussy"], a: 1, fb: "Giant Steps divide l'ottava in tre terze maggiori uguali: Si – Sol – Mi♭ – Si (Coltrane Changes). Ogni tonalità dura 2 tempi. È una riarmonizzazione radicale del circolo delle quinte — i musicisti dell'epoca faticavano a improvvisarci sopra a tempo." },
  { q: "Chopin trascorse la maggior parte della sua carriera a:", opts: ["Varsavia","Vienna","Parigi","Londra"], a: 2, fb: "Frédéric Chopin (1810–1849) si stabilì a Parigi nel 1831 e vi trascorse praticamente tutta la sua vita artistica, circondato dai più grandi artisti romantici (Liszt, Berlioz, Delacroix, George Sand). Parigi era allora il centro della vita musicale europea." },
  { q: "Mozart compone le sue tre sinfonie più celebri (n°39, 40, 41):", opts: ["A 12 anni","Nel 1788, in 6 settimane","Nei suoi primi anni viennesi","A Salisburgo sotto Colloredo"], a: 1, fb: "Le sinfonie n°39, 40 e 41 'Jupiter' vengono composte nell'estate del 1788 in poche settimane — uno dei prodigi creativi più stupefacenti della storia della musica. Mozart era allora in gravi difficoltà finanziarie." },
  { q: "Herbie Hancock in 'Maiden Voyage' (1965) usa accordi:", opts: ["Di dominante classici V7","Sospesi 7sus4 — senza terza, approccio quartal","Paralleli in stile Debussy","Del ciclo Coltrane Changes"], a: 1, fb: "Maiden Voyage usa sistematicamente accordi 7sus4 (quarta al posto della terza) — senza carattere maggiore/minore definito. Questo approccio 'quartal' (per quarte) crea un'ambiguità modale vicina a Debussy, una rivoluzione nel vocabolario jazz." },
  { q: "Bach componeva corali secondo la pratica:", opts: ["Barocca italiana (belcanto)","SATB (Soprano Alto Tenore Basso) a 4 voci indipendenti","Romantica con estensioni","Impressionista senza dominante"], a: 1, fb: "I corali di Bach sono scritti a 4 voci SATB. Ogni voce ha il proprio movimento melodico indipendente, senza quinte né ottave parallele. Questi corali sono ancora oggi il modello pedagogico del contrappunto a 4 voci." },
  { q: "Quale pianista romantico ha influenzato maggiormente il pianoforte jazz moderno?", opts: ["Liszt (tecnica virtuosistica)","Chopin (armonie, prestiti modali, texture)","Brahms (contrappunto)","Schubert (melodia)"], a: 1, fb: "Chopin è l'influenza pianistica più diretta sul jazz moderno. Bill Evans citava Chopin come riferimento principale per i suoi voicings, prestiti modali e texture arpeggiata. La parentela tra un notturno di Chopin e una ballata di Evans è sorprendente." },
  { q: "Cosa significa 'musica impressionista' in musica (per analogia con la pittura)?", opts: ["Musica che imita suoni della natura","Musica che crea un'impressione sensoriale attraverso il colore armonico e il timbro, senza narrazione direzionale","Musica dipinta su tele","Musica per accompagnare dipinti"], a: 1, fb: "Come i pittori impressionisti catturano un'impressione di luce (Monet, Renoir), Debussy e Ravel creano 'impressioni' sonore — La cattedrale sommersa, Il mare, Nuvole. L'armonia e il timbro hanno la precedenza sulla struttura narrativa." },
  { q: "Qual è la principale differenza tra Chopin e Debussy?", opts: ["Chopin è più antico","Chopin usa ancora dominanti funzionali; Debussy le evita","Debussy usa più prestiti modali","Chopin compone solo per orchestra"], a: 1, fb: "Chopin rimane nel quadro tonale — risolve i suoi V7 verso I, anche se ritarda, decora e prende in prestito. Debussy abbandona la risoluzione funzionale — i suoi accordi non 'cadono' verso I, scivolano nel colore. Questa differenza è fondamentale." },
  { q: "Qual è la differenza di 'basso' tra Bach e Mozart?", opts: ["Bach: solo ottave; Mozart: solo accordi","Bach: basso continuo melodicamente attivo; Mozart: basso di Alberti ripetitivo","Bach: basso in pizzicato; Mozart: arco","Nessuna differenza"], a: 1, fb: "Il basso di Bach è una voce a sé — fa contrappunto alla melodia con un proprio movimento melodico (discese cromatiche, salti espressivi). Il basso di Alberti di Mozart è una figura di accompagnamento ripetitiva che sostiene la melodia senza eguagliarla." },
  { q: "Jazz Evans vs Jazz Coltrane: principale differenza armonica?", opts: ["Evans è più veloce","Evans: voicings densi Maj7 e prestiti modali; Coltrane: ciclo di terze veloci (Coltrane Changes)","Coltrane usa più pentatonica","Evans compone, Coltrane improvvisa soltanto"], a: 1, fb: "Bill Evans sfrutta voicings ricchi di estensioni (Maj9, Maj7#11) e prestiti modali. Coltrane in Giant Steps usa i 'Coltrane Changes' — un ciclo di terze maggiori che cambia tonalità ogni 2 crome. Due linguaggi jazz distinti." },
  { q: "Rock modale vs rock tonale: differenza fondamentale?", opts: ["Il rock tonale è più veloce","Modale: nessun V7→I funzionale, progressioni cicliche; tonale: cadenze perfette V→I","Il rock modale usa solo la scala pentatonica","Il rock tonale è solo in modo minore"], a: 1, fb: "Il rock tonale usa le cadenze funzionali classiche (V7→I). Il rock modale evita deliberatamente il V7 — gli sostituisce il ♭VII (Misolidio) o lascia la progressione ciclica senza risoluzione. I–♭VII–IV–I può girare indefinitamente." },
  { q: "Chopin vs Tardo romanticismo (Rachmaninov): differenza di densità?", opts: ["Nessuna differenza — stessa epoca","Chopin: texture pianistica leggera, prestiti occasionali; Rachmaninov: densità orchestrale massima","Rachmaninov è più semplice","Chopin compone per orchestra, Rachmaninov per pianoforte solo"], a: 1, fb: "Chopin è pianistico e intimo — i suoi notturni hanno 3–4 voci leggere. Rachmaninov pensa orchestralmente — i suoi brani per pianoforte hanno la densità di una partitura orchestrale, con molte voci, raddoppi e prestiti drammatici permanenti." },
  { q: "Quale tecnica condividono lo stile jazz Evans e lo stile Chopin?", opts: ["La sostituzione di tritono","Il prestito modale dal modo minore parallelo","La scala per toni interi","Il basso di Alberti"], a: 1, fb: "Entrambi usano il prestito modale dal modo minore parallelo. Chopin: IVm, ♭VI in progressioni romantiche. Evans: DoMag7→Dom7→Fam7 in Peace Piece. Questa parentela non è casuale — Evans citava Chopin come influenza maggiore." },
  { q: "Quale tecnica è SOLO caratteristica del jazz tra gli stili studiati?", opts: ["Il prestito modale","La sostituzione di tritono (V7 → ♭II7)","Le progressioni per terze","Gli accordi paralleli"], a: 1, fb: "La sostituzione di tritono è un'invenzione del jazz bebop (anni '40). Non esiste nella musica classica di Bach, Mozart, Chopin o Debussy. Nessuno degli stili classici o rock la usa sistematicamente." },
  { q: "La progressione I–IV–V–I è caratteristica di quale/i stile/i?", opts: ["Solo Mozart","Bach e Mozart (ma non Debussy o jazz)","Tutti gli stili","Solo Bach"], a: 1, fb: "I–IV–V–I (cadenza perfetta) è la progressione tonale fondamentale — usata abbondantemente da Bach e Mozart. Chopin la usa ma arricchita (con prestiti). Debussy la evita. Il jazz la sostituisce con II–V–I. Il rock modale la evita (nessun V7)." },
  { q: "Quale stile usa i 'raddoppi' (note suonate in ottave simultanee) sistematicamente?", opts: ["Jazz post-bop","Tardo romanticismo (texture orchestrale densa)","Rock modale","Impressionismo"], a: 1, fb: "Il tardo romanticismo (Rachmaninov, Liszt) usa i raddoppi all'ottava — entrambe le mani che suonano la stessa melodia all'ottava — per raggiungere una potenza orchestrale sul pianoforte. Questa tecnica è raramente usata nel jazz o nell'impressionismo." },
  { q: "Distinguere Bach (barocco) e Brahms (romantico) nell'uso del contrappunto:", opts: ["Brahms non usa il contrappunto","Bach: fuga e contrappunto rigoroso; Brahms: contrappunto integrato in una texture romantica densa","Usano esattamente lo stesso tipo di contrappunto","Bach è più armonico di Brahms"], a: 1, fb: "Bach scrive fughe con contrappunto rigoroso (contrappunto invertibile, stretto). Brahms integra il contrappunto in una texture romantica — le sue opere hanno imitazioni, canoni, linee contrappuntistiche, ma immerse in una ricca armonia romantica." },
  { q: "Debussy e il jazz post-bop (Evans) condividono:", opts: ["Il circolo delle quinte","Il parallelismo e l'evitamento delle dominanti funzionali","Il basso di Alberti","Le cadenze perfette V→I"], a: 1, fb: "Entrambi evitano le cadenze V7→I e usano il parallelismo. Debussy: accordi di nona/Maj7 paralleli. Evans: blocchi di accordi che scorrono, prestiti modali. Questa parentela non è casuale — Evans era un assiduo lettore di Debussy." },
  { q: "Nello stile Mozart, l'armonia è 'economa' perché:", opts: ["Mozart non aveva accordi complessi","Usa principalmente I, IV, V7, IIm — pochi accordi diversi per frase","L'economia era una regola accademica dell'epoca","Componeva velocemente e non aveva tempo di complessizzare"], a: 1, fb: "Mozart sceglie deliberatamente la chiarezza armonica — una frase di 4 battute può usare solo 3–4 accordi. Questa economia non è una limitazione ma un'estetica: 'la perfezione è raggiunta quando non c'è più nulla da togliere'." },
  { q: "Si sente La♭Maj7 in una progressione in Do maggiore. Probabilmente è:", opts: ["Un accordo diatonico di Do maggiore","Un prestito modale ♭VI (da Do minore)","Una sostituzione di tritono","Un accordo di dominante secondaria"], a: 1, fb: "La♭Maj7 è ♭VI di Do maggiore — un accordo preso in prestito da Do minore (naturale/eolico) dove La♭ è il VI grado naturale. È il prestito modale ♭VIMaj7, molto usato nel romanticismo (Chopin, Rachmaninov) e nel rock modale." },
  { q: "In una progressione DoMag7–Si♭Mag7–La♭Mag7, si riconosce:", opts: ["Circolo delle quinte discendente","Armonizzazione Maj7 parallela discendente per toni interi","Sostituzione di tritono","Prestito dalla scala napoletana"], a: 1, fb: "DoMag7→Si♭Mag7→La♭Mag7: ogni accordo scende di un tono intero, stessa struttura Maj7 mantenuta. È il parallelismo impressionista di Debussy. Nessuna risoluzione di dominante, nessuna funzione armonica — puro colore." },
  { q: "SolMag – FaMag – DoMag – SolMag in Sol: il Fa è:", opts: ["La quinta di Do","Il ♭VII del modo Misolidio di Sol","Un prestito napoletano","Un accordo di sottodominante in Fa maggiore"], a: 1, fb: "In Sol maggiore diatonico, la settima è Fa# (non Fa naturale). Fa naturale è la settima minore — la nota caratteristica del modo Sol Misolidio. L'accordo FaMag è quindi l'accordo ♭VII misolidio, preso in prestito dal modo Misolidio." },
  { q: "Se Sol7 viene sostituito da Re♭7 in una progressione in Do, è:", opts: ["Un prestito modale","Una sostituzione di tritono (dal Corso 22)","Un accordo napoletano","Un'armonizzazione parallela"], a: 1, fb: "Sol7 → Re♭7 è la classica sostituzione di tritono. Sol e Re♭ sono a distanza di tritono (6 semitoni). Re♭7 risolve verso Do per movimento di ½ tono (Re♭→Do), creando il basso cromatico Re♭→Do invece del salto di quinta Sol→Do." },
  { q: "DoMag–Lam–Rem–Sol7–DoMag: è:", opts: ["I–♭VI–♭II–♭VII–I","I–VIm–IIm–V7–I — circolo delle quinte, stile barocco/classico","I–♭VII–IV–V–I — Misolidio","Rem9–Sol13–DoMag9 — jazz con estensioni"], a: 1, fb: "I–VIm–IIm–V7–I è il fondamentale circolo delle quinte discendente. Ogni accordo è a distanza di quinta dal precedente. È la progressione di Bach e del classicismo. Questa 'linea di basso' Do→La→Re→Sol→Do forma il fondamento del contrappunto barocco." },
  { q: "La nota Si♭ naturale in una progressione in Sol maggiore indica:", opts: ["Un errore armonico","Il modo Sol Misolidio (settima minore ♭7)","Un accordo napoletano","Una modulazione a Fa maggiore"], a: 1, fb: "In Sol maggiore, Si♭ non esiste (la settima è Si naturale). Si♭ indica il modo Sol Misolidio (dove la settima è minore) o una modulazione. In un contesto rock/modale, è quasi sempre Sol Misolidio — il colore rock per eccellenza." },
  { q: "Quale stile usa maggiormente le sospensioni espressive (ritardi 4–3, 7–6)?", opts: ["Debussy","Jazz bebop","Chopin e romanticismo","Bach barocco"], a: 2, fb: "Chopin e i romantici usano frequentemente le sospensioni (una nota è trattenuta da un accordo all'altro prima di risolvere). La sospensione 4–3 (quarta che risolve verso la terza) è particolarmente espressiva nei notturni di Chopin." },
  { q: "Cos'è una 'nota di passaggio cromatica' nelle voci interne?", opts: ["Una nota che non si sente","Una nota estranea che scende (o sale) cromaticamente tra due note dell'accordo","La fondamentale dell'accordo","La nota più alta della voce del soprano"], a: 1, fb: "Una nota di passaggio cromatica (es. La♭ tra La e Sol nella voce di contralto) scivola cromaticamente da una nota dell'accordo alla successiva. Chopin è maestro in questo — le sue voci interne hanno piccoli cromatismi espressivi che arricchiscono la texture." },
  { q: "La progressione Lam–Sol–Fa–Sol (in Do maggiore) è tipica di:", opts: ["Stile Chopin (prestito modale)","Rock modale eolico (VI–♭VII–♭VI–♭VII ciclico)","Jazz II–V–I","Bach circolo delle quinte"], a: 1, fb: "Lam–Sol–Fa–Sol in Do maggiore = VIm–V–IV–V. In La eolico (o Do maggiore modale), è la progressione folk/rock eolica — Stairway to Heaven (Led Zeppelin), Hotel California. Ciclica, senza dominante funzionale, colore modale naturale." },
  { q: "Quale stile combina maggiormente jazz e scrittura pianistica classica?", opts: ["Bebop tradizionale (Parker)","Jazz post-bop (Evans, Mehldau) — influenze di Debussy e Chopin","Rock modale","Neo-soul"], a: 1, fb: "Bill Evans e Brad Mehldau sono esplicitamente influenzati da Debussy (parallelismo) e Chopin (prestiti modali, texture arpeggiata). Evans studiò approfonditamente il repertorio pianistico classico. Il jazz post-bop è la sintesi più diretta tra jazz e pianoforte classico." },
  { q: "La 'coda' di un brano romantico usa spesso:", opts: ["Un ritorno improvviso al primo tema","Una lunga pedale di dominante prima della risoluzione finale","Un cambiamento di tonalità verso il relativo maggiore","Un motivo esclusivamente ritmico"], a: 1, fb: "La coda romantica usa frequentemente la pedale di dominante (nota V ripetuta nel basso mentre l'armonia cambia sopra) per creare una tensione massima prima della risoluzione finale. Rachmaninov e Tchaikovsky la usano per finali drammatici." },
  { q: "Quale affermazione descrive meglio lo stile di Brahms?", opts: ["Modernista e d'avanguardia","Contrappunto rigoroso in una texture romantica densa — sintesi di Bach e Beethoven","Puramente barocco, senza romanticismo","Jazz e impressionismo mescolati"], a: 1, fb: "Brahms è il 'conservatore romantico' — mantiene strutture classiche (contrappunto fugato, forme sonata rigorose) in un linguaggio armonico romantico denso. La sua sintesi di Bach (contrappunto) e Beethoven (sviluppo tematico) è unica." },
  { q: "Perché la melodia Do–Mi–Sol–Mi (arpeggio di Do) può essere armonizzata in quasi tutti gli stili?", opts: ["Perché contiene solo 2 note","Perché Do, Mi, Sol sono comuni a molti accordi — DoMag, Lam, Mim, FaMag7, La♭Mag7 (Mi=la 5ª), ecc.","Perché è in modo dorico","Perché è troppo semplice per porre vincoli"], a: 1, fb: "Do, Mi, Sol sono presenti in DoMag, Lam, Mim, FaMag (Do+Mi=3ª+5ª) e anche in accordi jazz (DoMag9, Lam7, ecc.). Questa flessibilità permette di armonizzare questa melodia in qualsiasi stile — ecco perché viene usata come melodia di prova pedagogica." },
];

const questionsPt: Question[] = [
  { q: "Qual progressão é característica do estilo de Bach?", opts: ["CMaj7–Si♭Maj7–Lá♭Maj7 (paralelismo)","DóMaj–Lám–Rém7–Sol7 (círculo de quintas)","SolMaj–FáMaj–DóMaj (Mixolídio)","Rém9–Sol13–DóMaj9 (extensões jazz)"], a: 1, fb: "I–VIm–IIm–V7 é o círculo de quintas descendente de Bach. Cada acorde está a distância de quinta do seguinte. A resolução Sol7→Dó resolve o trítono Si–Fá. É o movimento harmônico fundamental do contraponto barroco." },
  { q: "O baixo de Alberti (mão esquerda: grave–médio–agudo–médio) é característico de:", opts: ["Bach","Mozart","Chopin","Debussy"], a: 1, fb: "O baixo de Alberti é uma figura de acompanhamento característica do estilo clássico (Mozart, Haydn). A mão esquerda alterna baixo–acorde–médio–acorde, criando um acompanhamento fluente e simétrico sob a melodia da mão direita." },
  { q: "O empréstimo IVm (ex. Fám7 em Dó) nos noturnos é característico de:", opts: ["Bach","Mozart","Chopin","Debussy"], a: 2, fb: "Fám7 (IVm) em Dó maior é o empréstimo romântico por excelência de Chopin. Ele toma emprestado o IVm do modo menor paralelo (Dó menor), criando uma inesperada cor escura. Esta técnica é raramente usada por Bach ou Mozart." },
  { q: "Acordes Maj7 paralelos sem resolução de dominante são característicos de:", opts: ["Bach","Mozart","Chopin","Debussy"], a: 3, fb: "Debussy (impressionismo) faz deslizar blocos de acordes paralelos — Maj7, nona, acordes de quartas — sem nunca resolver para uma dominante. A cor tem precedência sobre a função harmônica." },
  { q: "II–V–I com extensões (9ª, 13ª) e voicings sem quinta caracterizam:", opts: ["Rock modal","Jazz post-bop (Evans)","Romântico","Barroco (Bach)"], a: 1, fb: "O jazz post-bop (Bill Evans, Brad Mehldau) usa II–V–I enriquecido com extensões — 9ª no II, 13ª no V, 9ª no I. Os voicings omitem a quinta (neutra) para manter 3ª, 7ª e extensões colorantes." },
  { q: "I–♭VII–IV–I sem dominante funcional é a progressão do:", opts: ["Estilo Chopin","Estilo barroco","Rock modal (Mixolídio)","Jazz bebop"], a: 2, fb: "I–♭VII–IV–I é a progressão do rock modal por excelência. O ♭VII vem do modo Mixolídio (sétima menor do tom). Esta progressão pode repetir-se indefinidamente sem resolução V→I — Norwegian Wood, Creep, Hey You." },
  { q: "Relações de terças descendentes e empréstimos dramáticos ao menor caracterizam:", opts: ["Estilo Mozart","Estilo Debussy","Estilo Bach","Romantismo tardio (Rachmaninov)"], a: 3, fb: "O romantismo tardio (Rachmaninov, Tchaikovsky) explora as relações de terças (I→♭VI→IV) e os empréstimos dramáticos ao menor. A densidade harmônica é máxima, com longos pedais de dominante." },
  { q: "Qual estilo usa o contraponto mais rigoroso?", opts: ["Jazz","Romântico","Bach (barroco)","Rock modal"], a: 2, fb: "Bach é o mestre do contraponto rigoroso. As suas regras: sem quintas paralelas, sem oitavas paralelas, resolução obrigatória do trítono, vozes internas com movimento melódico independente. Estas regras definem o contraponto a 4 vozes (SATB)." },
  { q: "Qual estilo mais evita as dominantes funcionais V7→I?", opts: ["Debussy (impressionismo)","Bach","Mozart","Jazz bebop"], a: 0, fb: "Debussy evita sistematicamente a resolução V7→I que considera demasiado previsível. Em vez disso, faz deslizar acordes paralelos ou usa escalas de tons inteiros. Esta liberdade face à tonalidade funcional é a assinatura do impressionismo." },
  { q: "A simetria de 4+4 compassos (antecedente + consequente) é característica de:", opts: ["Romântico","Jazz modal","Mozart (clássico)","Debussy"], a: 2, fb: "A forma período (4+4 compassos) é a unidade básica do estilo clássico vienense — Mozart, Haydn, Beethoven jovem. O antecedente (4 compassos terminando em V) é respondido pelo consequente (4 compassos terminando em I). Simetria e clareza absolutas." },
  { q: "A escala de tons inteiros (6 notas equidistantes, sem semitom) está associada a:", opts: ["Bach","Jazz bebop","Debussy","Rock modal"], a: 2, fb: "Debussy usa a escala de tons inteiros (C D E F# G# Si♭) como cor harmônica. Sem semitons, cria uma flutuação ambígua — sem sentido tonal estabelecido, sem sensível. É uma das assinaturas do impressionismo." },
  { q: "A substituição de trítono (Sol7 → Ré♭7) é mais usada no:", opts: ["Estilo Bach","Estilo Mozart","Estilo Debussy","Jazz (bebop/post-bop)"], a: 3, fb: "A substituição de trítono é uma técnica jazz desenvolvida no bebop (anos 1940). Substitui V7 pelo acorde de dominante situado um trítono mais abaixo, criando um baixo cromático descendente (♭II→I)." },
  { q: "As progressões cíclicas sem resolução final são típicas do:", opts: ["Bach","Mozart","Rock modal","Chopin"], a: 2, fb: "O rock modal usa progressões cíclicas (I–♭VII–IV–I) que podem repetir-se indefinidamente. Não há necessidade de resolução final V→I. Esta é a grande diferença com o estilo tonal clássico." },
  { q: "A máxima densidade harmônica com muitas vozes é característica do:", opts: ["Debussy","Mozart","Romantismo tardio","Jazz modal"], a: 2, fb: "Rachmaninov e Tchaikovsky escrevem texturas orquestralmente densas, com muitas vozes dobradas, acordes ricos e cromatismo generalizado. É o apogeu do romantismo — o exato oposto da economia de Mozart." },
  { q: "Qual progressão identifica mais claramente um estilo impressionista de Debussy?", opts: ["I–IV–V7–I","I–♭VI–IV–V","DóMaj7–Si♭Maj7–Lá♭Maj7–Sol♭Maj7","Rém9–Sol13–DóMaj9"], a: 2, fb: "Quatro Maj7 a descer por tons inteiros sem resolução — é o paralelismo impressionista de Debussy. Sem V7→I, sem tensão-resolução. Cada acorde é uma cor autônoma que 'desliza' para o seguinte." },
  { q: "Por que Bach evita as quintas paralelas?", opts: ["São demasiado difíceis de tocar","Criam uma 'quinta oculta' proibida no contraponto rigoroso","Não soam bem no cravo","Eram proibidas pela Igreja"], a: 1, fb: "As quintas paralelas criam uma 'quinta oculta' no contraponto rigoroso — duas vozes movem-se na mesma direção e pousam numa quinta. Este movimento reduz a independência das vozes, regra fundamental do contraponto a 4 vozes." },
  { q: "O 'círculo de quintas descendente' em Dó maior dá:", opts: ["Dó – Sol – Ré – Lá – Mi – Si – Fá# – Dó","Dó – Fá – Sidim – Mim – Lám – Rém – Sol – Dó","Dó – Lám – Mim – Sol – Rém – Fá – Dó","Dó – Rém – Mim – Fá – Sol – Lám – Sidim – Dó"], a: 1, fb: "O círculo de quintas descendente: Dó→Fá→Si→Mi→Lá→Ré→Sol→Dó. Em Dó maior diatônico: DóMaj – FáMaj – Sidim – Mim – Lám – Rém – Sol7 – DóMaj. Cada acorde desce uma quinta. É a progressão harmônica fundamental da música barroca." },
  { q: "Quantas notas tem a escala de tons inteiros de Debussy?", opts: ["5 (pentatônica)","6 (hexatônica)","7 (diatônica)","8 (octatônica)"], a: 1, fb: "A escala de tons inteiros é hexatônica — 6 notas equidistantes de um tom inteiro: C D E F# G# Si♭ (depois volta ao C). A ausência de semitom confere-lhe a sua característica ambiguidade tonal. Também é chamada 'escala de Debussy'." },
  { q: "Um voicing jazz 'sem quinta' omite a 5ª porque:", opts: ["A quinta é difícil de tocar","A quinta justa é acusticamente neutra e acrescenta pouca cor","A quinta não existe na escala pentatônica","A quinta cria um paralelismo proibido"], a: 1, fb: "A quinta justa é acusticamente a mais consonante depois da oitava — não colore o acorde. No jazz, mantém-se 3ª+7ª (guide-tones) e acrescenta-se 9ª, 11ª (#4), 13ª. A quinta é frequentemente omitida para manter os voicings compactos e expressivos." },
  { q: "A progressão I–♭VII–IV–I é Mixolídia porque:", opts: ["Contém 3 acordes maiores","O ♭VII vem do modo Mixolídio (sétima menor do tom)","Evita a tônica","Desce por quintas"], a: 1, fb: "Em Sol Mixolídio, a sétima é Fá natural (não Fá#). O acorde construído sobre este Fá natural é FáMaj (♭VIIMaj) — um acorde maior estranho a Sol maior mas natural em Sol Mixolídio. É a nota característica que distingue o Mixolídio do Jônico." },
  { q: "Um 'empréstimo do modo paralelo' significa:", opts: ["Tomar emprestado de uma tonalidade vizinha (distância de quinta)","Tomar emprestado do modo paralelo (mesma tônica, modo diferente: Dó maior ↔ Dó menor)","Tomar emprestado de uma escala pentatônica","Tomar emprestado de um acorde de dominante secundária"], a: 1, fb: "O empréstimo do modo paralelo usa acordes da tonalidade do mesmo nome mas de modo diferente. Em Dó maior, tomar emprestado Fám7 (IVm de Dó menor) é um empréstimo do modo paralelo — mesma tônica Dó, mas cor menor." },
  { q: "O ritmo harmônico 'rápido' no jazz significa:", opts: ["Andamento rápido","2 acordes por compasso ou mais (vs 1 acorde por 2–4 compassos)","Todos os acordes são colcheias","Muitas síncopas"], a: 1, fb: "O ritmo harmônico é a frequência das mudanças de acordes. No jazz bebop/post-bop, é frequentemente rápido: 2 acordes por compasso (ou mais nos Coltrane Changes). Mozart muda frequentemente de acorde a cada 2–4 compassos. Debussy pode manter um acorde 8 compassos." },
  { q: "Por que Debussy não usa a dominante funcional?", opts: ["Não conhecia este acorde","Prefere a cor harmônica à tensão-resolução funcional","A dominante é proibida no impressionismo","Usava apenas a escala pentatônica"], a: 1, fb: "Debussy procura a pura cor sonora — os acordes como texturas em vez de funções. A resolução V7→I cria uma tensão-resolução direcional que considera demasiado previsível. Prefere os deslizamentos paralelos que criam uma impressão, não uma direção." },
  { q: "O 'baixo contínuo' barroco consiste em:", opts: ["Uma linha de baixo contrapontística complexa","Uma linha de baixo cifrada que o cravo/organista realiza livremente com acordes","Um baixo em pizzicato das cordas","O baixo que toca o mesmo ritmo que a melodia"], a: 1, fb: "O baixo contínuo é uma linha de baixo cifrada — os números sobre as notas indicam que intervalos tocar. O instrumentista (cravo, órgão, alaúde) realiza os acordes livremente a partir desses números. Fundamental para a música barroca." },
  { q: "O que é uma 'relação de terça' romântica?", opts: ["Duas vozes a distância de terça","Movimento harmônico por terça entre fundamentais (ex. Dó→Lá♭, Lá♭→Fá) em vez de quinta","Um acorde de terça aumentada","A resolução da sensível para a tônica"], a: 1, fb: "A relação de terça é um movimento harmônico por terça entre fundamentais — típico do romantismo. DóMaj → Lá♭Maj (terça menor) ou DóMaj → MiMaj (terça maior). Estes movimentos criam surpresa harmônica mas mantêm coerência graças às notas comuns." },
  { q: "A 'cadência evitada' em Chopin significa:", opts: ["O V7 resolve para VI ou outro acorde em vez de I","Evitam-se todas as cadências nos noturnos","A peça não termina","Evita-se o acorde V7"], a: 0, fb: "A cadência evitada (ou interrompida): V7 não resolve para o esperado I mas para VIm (ou outro acorde). Em Dó: Sol7→Lám em vez de Sol7→Dó. Chopin usa frequentemente esta técnica para evitar uma conclusão demasiado previsível e manter a tensão narrativa." },
  { q: "Brahms dizia ouvir 'o passo de gigantes' atrás de si, referindo-se a:", opts: ["Apenas Beethoven","Bach e Beethoven","Mozart e Haydn","Wagner e Liszt"], a: 1, fb: "Brahms estava profundamente intimidado pelo legado de Bach (contraponto) e Beethoven (estrutura sinfônica). Publicou a sua 1ª Sinfonia apenas aos 43 anos, após mais de 20 anos de trabalho. A sua síntese destes dois gigantes define o seu estilo." },
  { q: "Qual álbum de Miles Davis (1959) é fundador do jazz modal?", opts: ["Kind of Blue","Bitches Brew","A Love Supreme","Giant Steps"], a: 0, fb: "Kind of Blue (1959) é o álbum de jazz mais vendido de todos os tempos e o manifesto do jazz modal. Bill Evans e Wynton Kelly ao piano. So What está em Ré dórico. Flamenco Sketches muda de modo em cada frase." },
  { q: "Qual peça de Debussy ilustra melhor o paralelismo de acordes?", opts: ["Arabesco n°1","A catedral submersa","Für Elise","O lago dos cisnes"], a: 1, fb: "A catedral submersa (Prelúdios, Livro I, n°10) de Debussy usa blocos de acordes de quintas paralelas evocando os órgãos de uma catedral debaixo de água. Os acordes paralelos sem resolução são a assinatura desta peça emblemática." },
  { q: "Brad Mehldau é conhecido pelas suas rearmonizações jazz de:", opts: ["Bach e Haendel","Radiohead, Beatles e Nick Drake","Brahms e Schubert","Wagner e Liszt"], a: 1, fb: "Brad Mehldau (nascido em 1970) reinterpreta regularmente canções dos Radiohead (Exit Music, Paranoid Android), Beatles (Blackbird, Martha My Dear) e Nick Drake em jazz post-bop. As suas rearmonizações combinam improvisação jazz e sensibilidade pop." },
  { q: "John Coltrane em 'Giant Steps' (1960) usa:", opts: ["Apenas substituições diatônicas","Um ciclo de terças maiores que divide a oitava em 3 partes iguais (Coltrane Changes)","Exclusivamente o modo dórico","A escala de tons inteiros de Debussy"], a: 1, fb: "Giant Steps divide a oitava em três terças maiores iguais: Si – Sol – Mi♭ – Si (Coltrane Changes). Cada tonalidade dura 2 tempos. É uma rearmonização radical do círculo de quintas — os músicos da época tinham dificuldade em improvisar sobre ela a tempo." },
  { q: "Chopin passou a maior parte da sua carreira em:", opts: ["Varsóvia","Viena","Paris","Londres"], a: 2, fb: "Frédéric Chopin (1810–1849) instalou-se em Paris em 1831 e aí passou praticamente toda a sua vida artística, rodeado dos maiores artistas românticos (Liszt, Berlioz, Delacroix, George Sand). Paris era então o centro da vida musical europeia." },
  { q: "Mozart compõe as suas três sinfonias mais célebres (n°39, 40, 41):", opts: ["Aos 12 anos","Em 1788, em 6 semanas","Nos seus primeiros anos vienenses","Em Salzburgo sob Colloredo"], a: 1, fb: "As sinfonias n°39, 40 e 41 'Júpiter' são compostas no verão de 1788 em poucas semanas — um dos feitos criativos mais espantosos da história da música. Mozart estava então em sérias dificuldades financeiras." },
  { q: "Herbie Hancock em 'Maiden Voyage' (1965) usa acordes:", opts: ["De dominante clássicos V7","Suspensos 7sus4 — sem terça, abordagem quartal","Paralelos ao estilo de Debussy","Do ciclo Coltrane Changes"], a: 1, fb: "Maiden Voyage usa sistematicamente acordes 7sus4 (quarta em vez de terça) — sem caráter maior/menor definido. Esta abordagem 'quartal' (por quartas) cria uma ambiguidade modal próxima de Debussy, uma revolução no vocabulário jazz." },
  { q: "Bach compunha corais segundo a prática:", opts: ["Barroca italiana (bel canto)","SATB (Soprano Contralto Tenor Baixo) a 4 vozes independentes","Romântica com extensões","Impressionista sem dominante"], a: 1, fb: "Os corais de Bach são escritos a 4 vozes SATB. Cada voz tem o seu próprio movimento melódico independente, sem quintas nem oitavas paralelas. Estes corais são ainda hoje o modelo pedagógico do contraponto a 4 vozes." },
  { q: "Qual pianista romântico mais influenciou o piano jazz moderno?", opts: ["Liszt (técnica virtuosística)","Chopin (harmonias, empréstimos modais, textura)","Brahms (contraponto)","Schubert (melodia)"], a: 1, fb: "Chopin é a influência pianística mais direta no jazz moderno. Bill Evans citava Chopin como referência principal para os seus voicings, empréstimos modais e textura arpegiada. O parentesco entre um noturno de Chopin e uma balada de Evans é surpreendente." },
  { q: "O que significa 'música impressionista' em música (por analogia com a pintura)?", opts: ["Música que imita sons da natureza","Música que cria uma impressão sensorial através da cor harmônica e do timbre, sem narração direcional","Música pintada em telas","Música para acompanhar pinturas"], a: 1, fb: "Tal como os pintores impressionistas capturam uma impressão de luz (Monet, Renoir), Debussy e Ravel criam 'impressões' sonoras — A catedral submersa, O mar, Nuvens. A harmonia e o timbre têm precedência sobre a estrutura narrativa." },
  { q: "Qual é a principal diferença entre Chopin e Debussy?", opts: ["Chopin é mais antigo","Chopin usa ainda dominantes funcionais; Debussy evita-as","Debussy usa mais empréstimos modais","Chopin compõe apenas para orquestra"], a: 1, fb: "Chopin permanece no quadro tonal — resolve os seus V7 para I, mesmo que atrase, decore e tome emprestado. Debussy abandona a resolução funcional — os seus acordes não 'caem' para I, deslizam em cor. Esta diferença é fundamental." },
  { q: "Qual é a diferença de 'baixo' entre Bach e Mozart?", opts: ["Bach: oitavas apenas; Mozart: apenas acordes","Bach: baixo contínuo melodicamente ativo; Mozart: baixo de Alberti repetitivo","Bach: baixo em pizzicato; Mozart: arco","Nenhuma diferença"], a: 1, fb: "O baixo de Bach é uma voz por si só — faz contraponto com a melodia, com o seu próprio movimento melódico (descidas cromáticas, saltos expressivos). O baixo de Alberti de Mozart é uma figura de acompanhamento repetitiva que apoia a melodia sem se igualar a ela." },
  { q: "Jazz Evans vs Jazz Coltrane: principal diferença harmônica?", opts: ["Evans é mais rápido","Evans: voicings densos Maj7 e empréstimos modais; Coltrane: ciclo de terças rápido (Coltrane Changes)","Coltrane usa mais pentatônica","Evans compõe, Coltrane apenas improvisa"], a: 1, fb: "Bill Evans explora voicings ricos em extensões (Maj9, Maj7#11) e empréstimos modais. Coltrane em Giant Steps usa os 'Coltrane Changes' — um ciclo de terças maiores que muda de tonalidade a cada 2 colcheias. Duas linguagens jazz distintas." },
  { q: "Rock modal vs rock tonal: diferença fundamental?", opts: ["O rock tonal é mais rápido","Modal: sem V7→I funcional, progressões cíclicas; tonal: cadências perfeitas V→I","O rock modal usa apenas a escala pentatônica","O rock tonal é apenas em modo menor"], a: 1, fb: "O rock tonal usa as cadências funcionais clássicas (V7→I). O rock modal evita deliberadamente o V7 — substitui-o pelo ♭VII (Mixolídio) ou deixa a progressão cíclica sem resolução. I–♭VII–IV–I pode rodar indefinidamente." },
  { q: "Chopin vs Romantismo tardio (Rachmaninov): diferença de densidade?", opts: ["Nenhuma diferença — mesma época","Chopin: textura pianística leve, empréstimos pontuais; Rachmaninov: densidade orquestral máxima","Rachmaninov é mais simples","Chopin compõe para orquestra, Rachmaninov para piano solo"], a: 1, fb: "Chopin é pianístico e intimista — os seus noturnos têm 3–4 vozes leves. Rachmaninov pensa orquestralmente — as suas peças para piano têm a densidade de uma partitura orquestral, com muitas vozes, dobragens e empréstimos dramáticos permanentes." },
  { q: "Qual técnica é partilhada pelo estilo jazz Evans e pelo estilo Chopin?", opts: ["A substituição de trítono","O empréstimo modal ao modo menor paralelo","A escala de tons inteiros","O baixo de Alberti"], a: 1, fb: "Ambos usam o empréstimo modal ao modo menor paralelo. Chopin: IVm, ♭VI em progressões românticas. Evans: DóMaj7→Dóm7→Fám7 em Peace Piece. Este parentesco não é casual — Evans citava Chopin como influência maior." },
  { q: "Qual técnica é APENAS característica do jazz entre os estilos estudados?", opts: ["O empréstimo modal","A substituição de trítono (V7 → ♭II7)","As progressões por terças","Os acordes paralelos"], a: 1, fb: "A substituição de trítono é uma invenção do jazz bebop (anos 1940). Não existe na música clássica de Bach, Mozart, Chopin ou Debussy. Nenhum dos estilos clássicos ou rock a usa sistematicamente." },
  { q: "A progressão I–IV–V–I é característica de qual/quais estilo/s?", opts: ["Apenas Mozart","Bach e Mozart (mas não Debussy ou jazz)","Todos os estilos","Apenas Bach"], a: 1, fb: "I–IV–V–I (cadência perfeita) é a progressão tonal fundamental — usada abundantemente por Bach e Mozart. Chopin usa-a mas enriquecida (com empréstimos). Debussy evita-a. O jazz substitui-a por II–V–I. O rock modal evita-a (sem V7)." },
  { q: "Qual estilo usa os 'dobramentos' (notas tocadas em oitavas simultâneas) sistematicamente?", opts: ["Jazz post-bop","Romantismo tardio (textura orquestral densa)","Rock modal","Impressionismo"], a: 1, fb: "O romantismo tardio (Rachmaninov, Liszt) usa os dobramentos em oitavas — ambas as mãos tocando a mesma melodia à oitava — para atingir uma potência orquestral no piano. Esta técnica é raramente usada no jazz ou no impressionismo." },
  { q: "Distinguir Bach (barroco) e Brahms (romântico) no uso do contraponto:", opts: ["Brahms não usa contraponto","Bach: fuga e contraponto rigoroso; Brahms: contraponto integrado numa textura romântica densa","Usam exatamente o mesmo tipo de contraponto","Bach é mais harmônico que Brahms"], a: 1, fb: "Bach escreve fugas com contraponto rigoroso (contraponto invertível, estretto). Brahms integra o contraponto numa textura romântica — as suas obras têm imitações, cânones, linhas contrapontísticas, mas imersas numa rica harmonia romântica." },
  { q: "Debussy e o jazz post-bop (Evans) partilham:", opts: ["O círculo de quintas","O paralelismo e a evitação das dominantes funcionais","O baixo de Alberti","As cadências perfeitas V→I"], a: 1, fb: "Ambos evitam as cadências V7→I e usam o paralelismo. Debussy: acordes de nona/Maj7 paralelos. Evans: blocos de acordes que deslizam, empréstimos modais. Este parentesco não é casual — Evans era um ávido leitor de Debussy." },
  { q: "No estilo Mozart, a harmonia é 'económica' porque:", opts: ["Mozart não tinha acordes complexos","Usa principalmente I, IV, V7, IIm — poucos acordes diferentes por frase","A economia era uma regra académica da época","Compunha rápido e não tinha tempo de complexificar"], a: 1, fb: "Mozart escolhe deliberadamente a clareza harmônica — uma frase de 4 compassos pode usar apenas 3–4 acordes. Esta economia não é uma limitação mas uma estética: 'a perfeição é atingida quando não há mais nada a retirar'." },
  { q: "Ouve-se Lá♭Maj7 numa progressão em Dó maior. Provavelmente é:", opts: ["Um acorde diatônico de Dó maior","Um empréstimo modal ♭VI (de Dó menor)","Uma substituição de trítono","Um acorde de dominante secundária"], a: 1, fb: "Lá♭Maj7 é ♭VI de Dó maior — um acorde emprestado de Dó menor (natural/eólio) onde Lá♭ é o VI grau natural. É o empréstimo modal ♭VIMaj7, muito usado no romantismo (Chopin, Rachmaninov) e no rock modal." },
  { q: "Numa progressão DóMaj7–Si♭Maj7–Lá♭Maj7, reconhece-se:", opts: ["Círculo de quintas descendente","Harmonização Maj7 paralela descendo por tons inteiros","Substituição de trítono","Empréstimo da escala napolitana"], a: 1, fb: "DóMaj7→Si♭Maj7→Lá♭Maj7: cada acorde desce um tom inteiro, mesma estrutura Maj7 mantida. É o paralelismo impressionista de Debussy. Sem resolução de dominante, sem função harmônica — pura cor." },
  { q: "SolMaj – FáMaj – DóMaj – SolMaj em Sol: o Fá é:", opts: ["A quinta de Dó","O ♭VII do modo Mixolídio de Sol","Um empréstimo napolitano","Um acorde de subdominante em Fá maior"], a: 1, fb: "Em Sol maior diatônico, a sétima é Fá# (não Fá natural). Fá natural é a sétima menor — a nota característica do modo Sol Mixolídio. O acorde FáMaj é portanto o acorde ♭VII Mixolídio, emprestado do modo Mixolídio." },
  { q: "Se Sol7 for substituído por Ré♭7 numa progressão em Dó, é:", opts: ["Um empréstimo modal","Uma substituição de trítono (do Curso 22)","Um acorde napolitano","Uma harmonização paralela"], a: 1, fb: "Sol7 → Ré♭7 é a substituição de trítono clássica. Sol e Ré♭ estão a distância de trítono (6 semitons). Ré♭7 resolve para Dó por movimento de ½ tom (Ré♭→Dó), criando o baixo cromático Ré♭→Dó em vez do salto de quinta Sol→Dó." },
  { q: "DóMaj–Lám–Rém–Sol7–DóMaj: é:", opts: ["I–♭VI–♭II–♭VII–I","I–VIm–IIm–V7–I — círculo de quintas, estilo barroco/clássico","I–♭VII–IV–V–I — Mixolídio","Rém9–Sol13–DóMaj9 — jazz com extensões"], a: 1, fb: "I–VIm–IIm–V7–I é o fundamental círculo de quintas descendente. Cada acorde está a distância de quinta do anterior. É a progressão de Bach e do classicismo. Esta 'linha de baixo' Dó→Lá→Ré→Sol→Dó forma o fundamento do contraponto barroco." },
  { q: "A nota Si♭ natural numa progressão em Sol maior indica:", opts: ["Um erro harmônico","O modo Sol Mixolídio (sétima menor ♭7)","Um acorde napolitano","Uma modulação para Fá maior"], a: 1, fb: "Em Sol maior, Si♭ não existe (a sétima é Si natural). Si♭ indica o modo Sol Mixolídio (onde a sétima é menor) ou uma modulação. Num contexto rock/modal, é quase sempre Sol Mixolídio — a cor rock por excelência." },
  { q: "Qual estilo mais usa as suspensões expressivas (retardos 4–3, 7–6)?", opts: ["Debussy","Jazz bebop","Chopin e romantismo","Bach barroco"], a: 2, fb: "Chopin e os românticos usam frequentemente as suspensões (uma nota é retida de um acorde para o seguinte antes de resolver). A suspensão 4–3 (quarta que resolve para terça) é particularmente expressiva nos noturnos de Chopin." },
  { q: "O que é uma 'nota de passagem cromática' nas vozes internas?", opts: ["Uma nota que não se ouve","Uma nota estranha que desce (ou sobe) cromaticamente entre duas notas do acorde","A fundamental do acorde","A nota mais alta da voz de soprano"], a: 1, fb: "Uma nota de passagem cromática (ex. Lá♭ entre Lá e Sol na voz de contralto) desliza cromaticamente de uma nota do acorde para a seguinte. Chopin é mestre nisso — as suas vozes internas têm pequenos cromatismos expressivos que enriquecem a textura." },
  { q: "A progressão Lám–Sol–Fá–Sol (em Dó maior) é típica de:", opts: ["Estilo Chopin (empréstimo modal)","Rock modal eólio (VI–♭VII–♭VI–♭VII cíclico)","Jazz II–V–I","Bach círculo de quintas"], a: 1, fb: "Lám–Sol–Fá–Sol em Dó maior = VIm–V–IV–V. Em Lá eólio (ou Dó maior modal), é a progressão folk/rock eólia — Stairway to Heaven (Led Zeppelin), Hotel California. Cíclica, sem dominante funcional, cor modal natural." },
  { q: "Qual estilo combina mais jazz e escrita pianística clássica?", opts: ["Bebop tradicional (Parker)","Jazz post-bop (Evans, Mehldau) — influências de Debussy e Chopin","Rock modal","Neo-soul"], a: 1, fb: "Bill Evans e Brad Mehldau são explicitamente influenciados por Debussy (paralelismo) e Chopin (empréstimos modais, textura arpegiada). Evans estudou aprofundadamente o repertório de piano clássico. O jazz post-bop é a síntese mais direta entre jazz e piano clássico." },
  { q: "A 'coda' de uma peça romântica usa frequentemente:", opts: ["Um regresso súbito ao primeiro tema","Um longo pedal de dominante antes da resolução final","Uma mudança de tonalidade para o relativo maior","Um motivo exclusivamente rítmico"], a: 1, fb: "A coda romântica usa frequentemente o pedal de dominante (nota V repetida no baixo enquanto a harmonia muda acima) para criar uma tensão máxima antes da resolução final. Rachmaninov e Tchaikovsky usam-na para finais dramáticos." },
  { q: "Qual afirmação descreve melhor o estilo de Brahms?", opts: ["Modernista e vanguardista","Contraponto rigoroso numa textura romântica densa — síntese de Bach e Beethoven","Puramente barroco, sem romantismo","Jazz e impressionismo misturados"], a: 1, fb: "Brahms é o 'conservador romântico' — mantém estruturas clássicas (contraponto fugado, formas sonata rigorosas) numa linguagem harmônica romântica densa. A sua síntese de Bach (contraponto) e Beethoven (desenvolvimento temático) é única." },
  { q: "Por que a melodia Dó–Mi–Sol–Mi (arpejo de Dó) pode ser harmonizada em quase todos os estilos?", opts: ["Porque contém apenas 2 notas","Porque Dó, Mi, Sol são comuns a muitos acordes — DóMaj, Lám, Mim, FáMaj7, Lá♭Maj7 (Mi=a 5ª), etc.","Porque está em modo dórico","Porque é demasiado simples para impor restrições"], a: 1, fb: "Dó, Mi, Sol estão presentes em DóMaj, Lám, Mim, FáMaj (Dó+Mi=3ª+5ª) e até em acordes jazz (DóMaj9, Lám7, etc.). Esta flexibilidade permite harmonizar esta melodia em qualquer estilo — é por isso que se usa como melodia de teste pedagógico." },
];

